def _assistant_match_micro_faq(role, q_norm):
    role_name = (role or '').strip().lower()
    text = _assistant_normalize_text(q_norm or '')
    if role_name not in {'super_admin', 'school_admin', 'teacher', 'student', 'parent'} or not text:
        return None
    tokens = set(text.split())
    ask_where = any(t in text for t in ('where', 'locate', 'find', 'open', 'go to'))
    ask_use = any(t in text for t in ('what is', 'used for', 'for what', 'purpose', 'button', 'tab', 'menu'))
    ask_how = any(t in text for t in ('how', 'steps', 'process', 'guide'))
    ask_yesno = any(t in text for t in ('can i', 'can we', 'must', 'required', 'need', 'is it', 'should i'))

    def _alias_score(alias_text):
        alias_norm = _assistant_normalize_text(alias_text or '')
        if not alias_norm:
            return 0
        if alias_norm in text:
            return 8 + len(alias_norm.split())
        parts = [p for p in alias_norm.split() if len(p) >= 3]
        if not parts:
            return 0
        hits = sum(1 for p in parts if p in tokens)
        if hits == len(parts):
            return 5 + hits
        if len(parts) >= 3 and hits >= (len(parts) - 1):
            return 3 + hits
        if len(parts) <= 2 and hits == len(parts):
            return 4 + hits
        return 0

    pool = list(APP_ASSISTANT_MICRO_FAQ.get('common') or [])
    pool.extend(list(APP_ASSISTANT_MICRO_FAQ.get(role_name) or []))
    best = None
    best_score = 0
    for entry in pool:
        aliases = [str(a).strip() for a in (entry.get('aliases') or []) if str(a).strip()]
        # Disambiguate "subject request" vs "data/privacy request".
        # Without this, short prompts like "subject request is for what" can
        # accidentally match the data-request FAQ because both contain "request".
        if 'subject request' in text:
            alias_join = ' '.join(_assistant_normalize_text(a) for a in aliases)
            if 'data request' in alias_join or 'privacy request' in alias_join or 'personal data request' in alias_join:
                continue
        score = 0
        for alias in aliases:
            score = max(score, _alias_score(alias))
        if score > best_score:
            best_score = score
            best = entry
    if not best or best_score < 5:
        return None
    answer = ''
    if ask_where and best.get('where'):
        answer = str(best.get('where') or '').strip()
    elif ask_use and best.get('use'):
        answer = str(best.get('use') or '').strip()
    elif ask_yesno and best.get('yesno'):
        answer = str(best.get('yesno') or '').strip()
    elif ask_how and best.get('how'):
        answer = str(best.get('how') or '').strip()
    if not answer:
        answer = str(best.get('use') or best.get('where') or best.get('yesno') or '').strip()
    if not answer:
        return None
    steps = [str(s).strip() for s in (best.get('steps') or []) if str(s).strip()][:6]
    next_question = str(best.get('next_question') or '').strip()
    return {
        'answer': answer,
        'steps': steps,
        'next_question': next_question or 'Do you want exact clicks for this workflow?',
        'confidence': 0.95 if best_score >= 8 else 0.88,
    }

def _assistant_infer_parent_school_id():
    keys = session.get('parent_student_keys') or []
    if not isinstance(keys, (list, tuple)):
        return ''
    for key in keys:
        raw = str(key or '').strip()
        if not raw or '::' not in raw:
            continue
        sid = raw.split('::', 1)[0].strip()
        if sid:
            return sid
    return ''

def _assistant_get_teacher_scope():
    role = (session.get('role') or '').strip().lower()
    school_id = (session.get('school_id') or '').strip()
    teacher_id = (session.get('user_id') or '').strip()
    if role != 'teacher' or not school_id or not teacher_id:
        return {
            'mode': 'none',
            'school_id': school_id,
            'teacher_id': teacher_id,
            'term': '',
            'academic_year': '',
            'class_assignments': [],
            'subject_assignments_by_class': {},
            'subject_assigned_classes': [],
            'all_scope_classes': [],
            'all_scope_subjects': [],
            'has_class_assignment': False,
            'has_subject_assignment': False,
        }

    school = get_school(school_id) or {}
    current_term = get_current_term(school)
    current_year = (school.get('academic_year', '') or '').strip()
    class_assignments = sorted(
        {
            (item or '').strip()
            for item in get_teacher_classes(
                school_id,
                teacher_id,
                term=current_term,
                academic_year=current_year,
            )
            if (item or '').strip()
        },
        key=lambda x: str(x).lower(),
    )
    subject_rows = get_teacher_subject_assignments(
        school_id,
        teacher_id=teacher_id,
        term=current_term,
        academic_year=current_year,
    )
    subject_map = {}
    for row in (subject_rows or []):
        cls = (row.get('classname') or '').strip()
        subj = normalize_subject_name(row.get('subject', ''))
        if not cls or not subj:
            continue
        subject_map.setdefault(cls, set()).add(subj)
    subject_assignments_by_class = {
        cls: sorted(values, key=lambda x: str(x).lower())
        for cls, values in sorted(subject_map.items(), key=lambda item: str(item[0]).lower())
    }
    subject_assigned_classes = sorted(subject_assignments_by_class.keys(), key=lambda x: str(x).lower())
    all_scope_classes = sorted(set(class_assignments) | set(subject_assigned_classes), key=lambda x: str(x).lower())
    all_scope_subjects = sorted(
        {subj for values in subject_assignments_by_class.values() for subj in values},
        key=lambda x: str(x).lower(),
    )
    has_class_assignment = bool(class_assignments)
    has_subject_assignment = bool(all_scope_subjects)
    if has_class_assignment and has_subject_assignment:
        mode = 'class_and_subject'
    elif has_class_assignment:
        mode = 'class_only'
    elif has_subject_assignment:
        mode = 'subject_only'
    else:
        mode = 'none'
    return {
        'mode': mode,
        'school_id': school_id,
        'teacher_id': teacher_id,
        'term': current_term,
        'academic_year': current_year,
        'class_assignments': class_assignments,
        'subject_assignments_by_class': subject_assignments_by_class,
        'subject_assigned_classes': subject_assigned_classes,
        'all_scope_classes': all_scope_classes,
        'all_scope_subjects': all_scope_subjects,
        'has_class_assignment': has_class_assignment,
        'has_subject_assignment': has_subject_assignment,
    }

