def _assistant_apply_typo_map(value):
    text = str(value or '').strip().lower()
    if not text:
        return ''
    for src, dst in (APP_ASSISTANT_TYPO_MAP or {}).items():
        src_n = str(src or '').strip().lower()
        dst_n = str(dst or '').strip().lower()
        if src_n and dst_n and src_n in text:
            text = text.replace(src_n, dst_n)
    for src, dst in (APP_ASSISTANT_FALLBACK_LANGUAGE_MAP or {}).items():
        src_n = str(src or '').strip().lower()
        dst_n = str(dst or '').strip().lower()
        if not src_n or not dst_n:
            continue
        pattern = r'(?<![a-z0-9])' + re.escape(src_n) + r'(?![a-z0-9])'
        text = re.sub(pattern, dst_n, text)
    return text

def _assistant_normalize_text(text):
    value = (text or '').strip().lower()
    value = _assistant_apply_typo_map(value)
    value = re.sub(r'[^a-z0-9]+', ' ', value)
    return re.sub(r'\s+', ' ', value).strip()

def _assistant_expand_tokens_with_fuzzy(tokens, vocabulary):
    expanded = set(tokens or [])
    vocab = sorted({str(v or '').strip().lower() for v in (vocabulary or []) if str(v or '').strip()})
    if not vocab:
        return expanded
    for token in list(expanded):
        if len(token) < 4 or token in vocab:
            continue
        matches = difflib.get_close_matches(token, vocab, n=2, cutoff=APP_ASSISTANT_FUZZY_CUTOFF)
        for match in matches:
            expanded.add(match)
    return expanded

def _assistant_execution_intent_detected(q_low):
    text = (q_low or '').strip().lower()
    if not text:
        return False
    # Keep guidance questions out of execution-intent blocking.
    if (
        text.startswith(('how ', 'where ', 'what ', 'why ', 'can ', 'is ', 'should ', 'which ', 'who '))
        or 'how to' in text
        or 'for what' in text
    ):
        return False
    command_phrases = (
        'do it',
        'do all',
        'execute',
        'run it',
        'run this',
        'fix it',
        'delete',
        'remove',
        'publish now',
        'send now',
        'create now',
        'update now',
    )
    return any(v in text for v in command_phrases)

def _assistant_is_greeting(q_norm):
    tokens = set((q_norm or '').split())
    if not tokens:
        return False
    if tokens <= {'hi'} or tokens <= {'hello'}:
        return True
    if q_norm in {'help', 'guide'}:
        return True
    if 'what can you do' in q_norm:
        return True
    return False

def _assistant_expand_indirect_intent(role, q_norm):
    role_aliases = APP_ASSISTANT_INDIRECT_ALIASES.get((role or '').strip().lower(), [])
    if not q_norm:
        return ''
    expanded = q_norm
    for alias_terms, canonical in role_aliases:
        for term in alias_terms:
            term_norm = _assistant_normalize_text(term)
            if term_norm and term_norm in q_norm:
                expanded = f'{expanded} {_assistant_normalize_text(canonical)}'.strip()
                break
            if term_norm and len(term_norm) >= 5:
                sim = difflib.SequenceMatcher(None, q_norm, term_norm).ratio()
                if sim >= 0.84:
                    expanded = f'{expanded} {_assistant_normalize_text(canonical)}'.strip()
                    break
    return expanded

def _assistant_extract_route_hint(text):
    raw = (text or '').strip().lower()
    if not raw:
        return ''
    match = re.search(r'(https?://[^\s]+|/[a-z0-9\-_./]+)', raw)
    if not match:
        return ''
    candidate = match.group(1).strip()
    if candidate.startswith('http://') or candidate.startswith('https://'):
        try:
            parsed = urllib.parse.urlparse(candidate)
            path = (parsed.path or '').strip().lower()
        except Exception:
            path = ''
    else:
        path = candidate
    path = re.sub(r'/+', '/', path).strip()
    if not path.startswith('/'):
        return ''
    return path.rstrip('/') or '/'

def _assistant_clean_source_page(value):
    raw = str(value or '').strip()
    if not raw:
        return ''
    route = _assistant_extract_route_hint(raw)
    if route:
        return route[:220]
    if raw.startswith('/'):
        cleaned = raw.split('?', 1)[0].split('#', 1)[0].strip().lower()
        return cleaned[:220]
    return ''

def _assistant_parse_steps_json(steps_json):
    try:
        rows = json.loads(steps_json or '[]')
        if not isinstance(rows, list):
            return []
        return [str(s).strip() for s in rows if str(s).strip()][:6]
    except Exception:
        return []

def _assistant_build_bpe_corpus(role, school_id='', source_page=''):
    role_name = (role or '').strip().lower()
    seed_texts = []
    for item in _assistant_role_kb(role_name):
        title = str(item.get('title') or '').strip()
        summary = str(item.get('summary') or '').strip()
        if title:
            seed_texts.append(title)
        if summary:
            seed_texts.append(summary)
        for kw in (item.get('keywords') or []):
            kw_text = str(kw or '').strip()
            if kw_text:
                seed_texts.append(kw_text)

    page_key = _assistant_clean_source_page(source_page)
    try:
        if ensure_extended_features_schema():
            with db_connection() as conn:
                c = conn.cursor()
                db_execute(
                    c,
                    """SELECT question_norm
                       FROM assistant_local_qa
                       WHERE COALESCE(school_id, '') = COALESCE(?, '')
                         AND LOWER(role) = ?
                         AND (COALESCE(source_page, '') = '' OR COALESCE(source_page, '') = COALESCE(?, ''))
                       ORDER BY
                         (COALESCE(helpful_count, 0) - COALESCE(not_helpful_count, 0)) DESC,
                         COALESCE(usage_count, 0) DESC,
                         updated_at DESC
                       LIMIT 320""",
                    ((school_id or ''), role_name, page_key),
                )
                rows = c.fetchall() or []
            for row in rows:
                qn = str((row[0] or '')).strip()
                if qn:
                    seed_texts.append(qn)
    except Exception as exc:
        _log_suppressed_exception('_assistant_build_bpe_corpus', exc)

    words = []
    for text in seed_texts:
        for token in _assistant_normalize_text(text).split():
            if len(token) >= 2:
                words.append(token)
    return words[:6000]

def _assistant_train_bpe_merges(words, max_merges=90):
    if not words:
        return []
    vocab = Counter()
    for w in words:
        chars = tuple(list(w) + ['</w>'])
        vocab[chars] += 1
    merges = []
    for _ in range(max(1, int(max_merges or APP_ASSISTANT_BPE_MAX_MERGES))):
        pair_counts = Counter()
        for pieces, freq in vocab.items():
            if len(pieces) < 2:
                continue
            for i in range(len(pieces) - 1):
                pair_counts[(pieces[i], pieces[i + 1])] += freq
        if not pair_counts:
            break
        best_pair, best_freq = pair_counts.most_common(1)[0]
        if int(best_freq or 0) < 2:
            break
        merges.append(best_pair)
        new_vocab = Counter()
        for pieces, freq in vocab.items():
            merged = []
            i = 0
            while i < len(pieces):
                if i < len(pieces) - 1 and pieces[i] == best_pair[0] and pieces[i + 1] == best_pair[1]:
                    merged.append(pieces[i] + pieces[i + 1])
                    i += 2
                else:
                    merged.append(pieces[i])
                    i += 1
            new_vocab[tuple(merged)] += freq
        vocab = new_vocab
    return merges

def _assistant_get_bpe_merges(role, school_id='', source_page=''):
    if not APP_ASSISTANT_ENABLE_BPE:
        return []
    role_name = (role or '').strip().lower()
    school_key = (school_id or '').strip()
    page_key = _assistant_clean_source_page(source_page)
    cache_key = f'{role_name}|{school_key}|{page_key}'
    now_ts = int(time.time())
    with _ASSISTANT_BPE_LOCK:
        cached = _ASSISTANT_BPE_CACHE.get(cache_key) or {}
        if cached and (now_ts - int(cached.get('ts') or 0) <= APP_ASSISTANT_BPE_RETRAIN_SECONDS):
            return list(cached.get('merges') or [])
    corpus = _assistant_build_bpe_corpus(role_name, school_id=school_key, source_page=page_key)
    merges = _assistant_train_bpe_merges(corpus, max_merges=APP_ASSISTANT_BPE_MAX_MERGES)
    with _ASSISTANT_BPE_LOCK:
        _ASSISTANT_BPE_CACHE[cache_key] = {'ts': now_ts, 'merges': list(merges or [])}
    return merges

def _assistant_bpe_encode_word(word, merges):
    pieces = [ch for ch in str(word or '').strip() if ch] + ['</w>']
    if len(pieces) <= 2:
        return [str(word or '').strip().lower()] if str(word or '').strip() else []
    for left, right in (merges or []):
        out = []
        i = 0
        while i < len(pieces):
            if i < len(pieces) - 1 and pieces[i] == left and pieces[i + 1] == right:
                out.append(left + right)
                i += 2
            else:
                out.append(pieces[i])
                i += 1
        pieces = out
    return [p for p in pieces if p and p != '</w>']

def _assistant_bpe_piece_set(text, merges):
    norm = _assistant_normalize_text(text)
    if not norm:
        return set()
    result = set()
    for word in norm.split():
        encoded = _assistant_bpe_encode_word(word, merges)
        for piece in encoded[:8]:
            if len(piece) >= 2:
                result.add(piece)
        if len(result) >= 260:
            break
    return result

def _assistant_is_page_help_question(q_norm):
    checks = (
        'what can i do',
        'what can i do here',
        'what can i do in this page',
        'what can i do on this page',
        'what is this page',
        'this page is for',
        'this page for',
        'use of this page',
        'purpose of this page',
        'how to use this page',
    )
    return any(token in (q_norm or '') for token in checks)

def _assistant_is_contextual_page_question(q_norm):
    text = (q_norm or '').strip()
    if not text:
        return False
    hints = (
        'this page',
        'on this page',
        'in this page',
        'here',
        'this tab',
        'this section',
        'this menu',
        'this button',
        'on this screen',
        'in here',
        'what can i do',
        'how do i use this',
        'what is this for',
    )
    return any(h in text for h in hints)

def _assistant_is_unclear_question(q_norm):
    text = _assistant_normalize_text(q_norm or '')
    if not text:
        return True
    generic_tokens = {
        'yes', 'no', 'ok', 'okay', 'help', 'hello', 'hi', 'please',
        'do', 'it', 'continue', 'next', 'again', 'why', 'how', 'what',
        'not working', 'not clear', 'problem', 'issue', 'error',
    }
    if text in generic_tokens:
        return True
    if len(text.split()) <= 2 and text not in {'add student', 'view result', 'reset password'}:
        return True
    vague_phrases = (
        'it is not working',
        'still not working',
        'what of this',
        'how now',
        'no show',
        'e no clear',
        'i no understand',
        'not clear',
        'do it',
    )
    return any(p in text for p in vague_phrases)

def _assistant_page_relevance_score(q_norm, page_guidance):
    text = _assistant_normalize_text(q_norm or '')
    if not text or not isinstance(page_guidance, dict):
        return 0
    tokens = set(text.split())
    title = _assistant_normalize_text(page_guidance.get('title') or '')
    summary = _assistant_normalize_text(page_guidance.get('summary') or '')
    steps = ' '.join(_assistant_normalize_text(s) for s in (page_guidance.get('steps') or []))
    keywords = set((title + ' ' + summary + ' ' + steps).split())
    overlap = len(tokens & keywords)
    score = overlap
    if title and title in text:
        score += 3
    if _assistant_is_contextual_page_question(text):
        score += 2
    return score

def _assistant_is_purpose_question(q_norm):
    text = (q_norm or '')
    checks = (
        'what is',
        'what are',
        'used for',
        'use for',
        'purpose of',
        'meaning of',
        'what does',
    )
    return any(token in text for token in checks) and any(token in text for token in ('use', 'used', 'purpose', 'what is', 'what are', 'what does'))

def _assistant_is_overview_question(q_norm):
    text = (q_norm or '')
    checks = (
        'how things are done in app',
        'how things are done',
        'how app works',
        'how this app works',
        'how does this app work',
        'how workflow works',
        'explain app workflow',
        'what can i do in app',
        'guide me app flow',
        'overall workflow',
    )
    return any(token in text for token in checks)

def _assistant_build_page_answer(page_guidance, role='', nav_group_hint=''):
    role_name = (role or '').strip().lower()
    if not isinstance(page_guidance, dict):
        return ('This page contains role-specific actions.', [])
    title = str(page_guidance.get('title') or '').strip()
    summary = str(page_guidance.get('summary') or '').strip()
    raw_steps = [str(s).strip() for s in (page_guidance.get('steps') or []) if str(s).strip()]
    steps = raw_steps[:4]
    if nav_group_hint:
        steps = [str(nav_group_hint).strip()] + steps
    role_prefix = {
        'school_admin': 'As school admin,',
        'teacher': 'As teacher,',
        'parent': 'As parent,',
        'student': 'As student,',
        'super_admin': 'As super admin,',
    }.get(role_name, '')
    if title and summary:
        answer = f'{role_prefix} you are on {title}. {summary}'.strip() if role_prefix else f'You are on {title}. {summary}'
    elif summary:
        answer = f'{role_prefix} {summary}'.strip() if role_prefix else summary
    elif title:
        answer = f'{role_prefix} you are on {title}.'.strip() if role_prefix else f'You are on {title}.'
    else:
        answer = f'{role_prefix} this page contains role-specific actions.'.strip() if role_prefix else 'This page contains role-specific actions.'
    if role_name == 'school_admin' and title.lower() == 'school admin dashboard':
        steps.append('Use sidebar groups (Students, Academics, Monitoring, Communication, System, Support) to open exact workflows.')
    elif role_name == 'teacher':
        steps.append('Actions here apply only to your assigned class/subject scope for this term/year.')
    elif role_name == 'parent':
        steps.append('This view should stay child-specific; switch child first if multiple children are linked.')
    elif role_name == 'student':
        steps.append('If a page action is blocked, contact your class teacher or school admin for permission.')
    elif role_name == 'super_admin':
        steps.append('Confirm target school before saving because super admin changes can affect multiple schools.')
    # Keep steps clean and unique.
    cleaned = []
    seen = set()
    for step in steps:
        key = _assistant_normalize_text(step)
        if key and key not in seen:
            cleaned.append(step)
            seen.add(key)
        if len(cleaned) >= 5:
            break
    return (answer, cleaned)

def _assistant_page_next_question(role='', page_guidance=None):
    role_name = (role or '').strip().lower()
    title = str((page_guidance or {}).get('title') or 'this page').strip() or 'this page'
    prompts = {
        'school_admin': f'Do you want exact clicks for the {title} workflow?',
        'teacher': f'Do you want exact steps for {title} based on your assigned class/subject?',
        'parent': f'Do you want step-by-step guidance on {title} for one specific child?',
        'student': f'Do you want step-by-step actions to complete {title} as a student?',
        'super_admin': f'Do you want safe step-by-step actions for {title} across schools?',
    }
    return prompts.get(role_name, 'Do you want step-by-step actions for this page right now?')

def _assistant_build_low_confidence_question(role='', q_norm='', page_guidance=None, ranked_topics=None, links=None):
    role_name = (role or '').strip().lower()
    text = _assistant_normalize_text(q_norm or '')
    title = str((page_guidance or {}).get('title') or '').strip()
    if title:
        return f'Are you asking about {title}?'

    if role_name == 'school_admin':
        if any(t in text for t in ('student', 'admission', 'intake', 'register')):
            return 'Do you mean Add Students or View Students?'
        if any(t in text for t in ('subject', 'curriculum', 'offer')):
            return 'Do you mean Class Subjects setup?'
        if any(t in text for t in ('publish', 'approve', 'result')):
            return 'Do you mean Publish Results workflow?'
        if any(t in text for t in ('dispute', 'complaint')):
            return 'Do you mean Result Disputes workflow?'
        if any(t in text for t in ('audit', 'promotion')):
            return 'Do you mean Promotion Audit or Score Audit?'
        if any(t in text for t in ('message', 'communication', 'notice')):
            return 'Do you mean Messages workflow?'
    elif role_name == 'teacher':
        if any(t in text for t in ('score', 'mark', 'csv')):
            return 'Do you mean Enter Scores or Upload CSV?'
        if any(t in text for t in ('attendance', 'period')):
            return 'Do you mean Attendance workflow?'
        if any(t in text for t in ('assignment', 'note', 'message')):
            return 'Do you mean Send Assignment/Note workflow?'
        if any(t in text for t in ('class list', 'student list', 'recent students')):
            return 'Do you mean Classroom > Class List?'
        if any(t in text for t in ('notification', 'alert', 'missing score')):
            return 'Do you mean Teacher Notifications page?'
    elif role_name == 'parent':
        if any(t in text for t in ('result', 'score', 'report')):
            return 'Do you mean View Child Result or Compare Results?'
        if any(t in text for t in ('attendance', 'absent')):
            return 'Do you mean Parent Attendance view?'
        if any(t in text for t in ('timetable', 'schedule', 'period')):
            return 'Do you mean Parent Timetable view?'
    elif role_name == 'student':
        if any(t in text for t in ('result', 'score', 'report')):
            return 'Do you mean Student View Result page?'
        if any(t in text for t in ('message', 'notice', 'notification')):
            return 'Do you mean Student Messages page?'
        if any(t in text for t in ('password', 'login', 'security')):
            return 'Do you mean Change Password page?'
    elif role_name == 'super_admin':
        if any(t in text for t in ('school', 'add', 'create')):
            return 'Do you mean Add School workflow?'
        if any(t in text for t in ('view', 'manage', 'operation')):
            return 'Do you mean View Schools management?'
        if any(t in text for t in ('privacy', 'data request', 'personal data')):
            return 'Do you mean Privacy Requests workflow?'
        if any(t in text for t in ('issue', 'report', 'bug')):
            return 'Do you mean Reported Issues queue?'

    if ranked_topics:
        top = ranked_topics[0][1] if isinstance(ranked_topics[0], (list, tuple)) and len(ranked_topics[0]) > 1 else None
        top_title = str((top or {}).get('title') or '').strip()
        if top_title:
            return f'Are you asking about {top_title}?'

    labels = [str(item.get('label') or '').strip() for item in (links or []) if str(item.get('label') or '').strip()][:3]
    if len(labels) == 1:
        return f'Are you asking about {labels[0]}?'
    if len(labels) == 2:
        return f'Do you mean {labels[0]} or {labels[1]}?'
    if len(labels) >= 3:
        return f'Do you mean {labels[0]}, {labels[1]}, or {labels[2]}?'

    defaults = {
        'school_admin': 'Do you mean Add Students, Class Subjects, Publish Results, or Messages?',
        'teacher': 'Do you mean Enter Scores, Class List, Messages, or Notifications?',
        'parent': 'Do you mean Child Result, Attendance, or Timetable?',
        'student': 'Do you mean View Result, Messages, or Change Password?',
        'super_admin': 'Do you mean Add School, View Schools, Privacy Requests, or Reported Issues?',
    }
    return defaults.get(role_name, 'Which exact page do you mean?')

def _assistant_extract_nav_group(nav_group_hint=''):
    text = str(nav_group_hint or '').strip()
    if not text:
        return ''
    m = re.search(r'`([^`]+)`', text)
    if m:
        return str(m.group(1) or '').strip()
    return ''

def _assistant_build_click_path(role='', page_guidance=None, nav_group_hint='', source_page='', fallback_label='', links=None):
    role_name = (role or '').strip().lower()
    title = str((page_guidance or {}).get('title') or '').strip()
    group = _assistant_extract_nav_group(nav_group_hint)
    route = _assistant_clean_source_page(source_page or '')
    if group and title:
        return f'Sidebar -> {group} -> {title}'
    if role_name in {'school_admin', 'teacher'} and title:
        return f'Sidebar -> {title}'
    if role_name in {'parent', 'student', 'super_admin'} and title:
        return f'Sidebar -> {title}'
    if route and route != '/':
        parts = [p for p in route.strip('/').split('/') if p]
        if parts:
            label = ' '.join(p.replace('-', ' ') for p in parts[-2:])
            label = re.sub(r'\s+', ' ', label).strip().title()
            if label:
                return f'Sidebar -> {label}'
    fallback = str(fallback_label or '').strip()
    if not fallback and isinstance(links, list):
        for item in links:
            label = str((item or {}).get('label') or '').strip()
            if label:
                fallback = label
                break
    if fallback:
        return f'Sidebar -> {fallback}'
    if role_name in {'school_admin', 'teacher', 'parent', 'student', 'super_admin'}:
        return 'Sidebar -> Dashboard'
    return 'Sidebar'

def _assistant_role_scope_note(role='', q_norm='', teacher_scope=None):
    role_name = (role or '').strip().lower()
    text = _assistant_normalize_text(q_norm or '')
    if not role_name or not text:
        return ''
    asks_permission = any(tok in text for tok in (
        'can we', 'allowed', 'permission', 'access', 'role', 'work of', 'do the work', 'what admin do', 'what teacher do'
    ))
    if 'can i' in text and not text.startswith('where can i '):
        asks_permission = True
    mentions_other_role = (
        (role_name != 'teacher' and bool(re.search(r'\bteacher\b', text)))
        or (role_name != 'school_admin' and bool(re.search(r'\bschool admin\b', text)))
        or (role_name != 'super_admin' and bool(re.search(r'\bsuper admin\b', text)))
    )
    if not asks_permission and not mentions_other_role:
        return ''

    if role_name == 'school_admin':
        return 'Role scope: As School Admin, you can manage school setup, users, assignments, and publishing workflows; you cannot perform super-admin global control actions.'
    if role_name == 'teacher':
        scope_mode = ((teacher_scope or {}).get('mode') or '').strip().lower()
        if scope_mode in {'none', ''}:
            return 'Role scope: As Teacher, you can use teacher pages; score/attendance actions are limited until assignment is added by school admin.'
        return 'Role scope: As Teacher, you can enter scores and manage assigned class/subject workflows; you cannot change school-wide settings or super-admin operations.'
    if role_name == 'parent':
        return 'Role scope: As Parent, you can view linked-child records and submit disputes/requests; you cannot edit school academic records directly.'
    if role_name == 'student':
        return 'Role scope: As Student, you can view your own records/messages and submit allowed requests; you cannot change teacher/admin-managed data.'
    if role_name == 'super_admin':
        return 'Role scope: As Super Admin, you can manage global platform operations; school-level record edits are done through school-admin workflows.'
    return ''

def get_assistant_learning_signal(school_id, role='', question='', source_page='', days=45):
    sid = (school_id or '').strip()
    role_name = (role or '').strip().lower()
    question_text = str(question or '').strip()
    if not sid or not role_name or not question_text or not ensure_extended_features_schema():
        return {'needs_update': False, 'helpful': 0, 'not_helpful': 0, 'unresolved_hits': 0, 'avg_confidence': 0.0}
    days = max(7, min(int(days or 45), 180))
    q_norm = _assistant_normalize_text(question_text)
    if not q_norm:
        return {'needs_update': False, 'helpful': 0, 'not_helpful': 0, 'unresolved_hits': 0, 'avg_confidence': 0.0}
    feedback_rows = []
    query_rows = []
    try:
        with db_connection() as conn:
            c = conn.cursor()
            db_execute(
                c,
                """SELECT question, helpful
                   FROM assistant_feedback_logs
                   WHERE school_id = ?
                     AND LOWER(role) = ?
                     AND created_at >= (CURRENT_TIMESTAMP - (? || ' days')::interval)
                     AND COALESCE(TRIM(question), '') <> ''
                   ORDER BY created_at DESC
                   LIMIT 300""",
                (sid, role_name, str(days)),
            )
            feedback_rows = c.fetchall() or []
            db_execute(
                c,
                """SELECT question, COALESCE(unresolved, 0), COALESCE(confidence, 0.0)
                   FROM assistant_query_logs
                   WHERE school_id = ?
                     AND LOWER(role) = ?
                     AND created_at >= (CURRENT_TIMESTAMP - (? || ' days')::interval)
                     AND COALESCE(TRIM(question), '') <> ''
                   ORDER BY created_at DESC
                   LIMIT 300""",
                (sid, role_name, str(days)),
            )
            query_rows = c.fetchall() or []
    except Exception:
        return {'needs_update': False, 'helpful': 0, 'not_helpful': 0, 'unresolved_hits': 0, 'avg_confidence': 0.0}

    helpful = 0
    not_helpful = 0
    unresolved_hits = 0
    conf_vals = []
    for row in feedback_rows:
        row_q = _assistant_normalize_text(row[0] or '')
        if not row_q:
            continue
        sim = difflib.SequenceMatcher(None, q_norm, row_q).ratio()
        if sim < 0.88:
            continue
        if int(row[1] or 0) == 1:
            helpful += 1
        else:
            not_helpful += 1
    for row in query_rows:
        row_q = _assistant_normalize_text(row[0] or '')
        if not row_q:
            continue
        sim = difflib.SequenceMatcher(None, q_norm, row_q).ratio()
        if sim < 0.88:
            continue
        unresolved_hits += int(row[1] or 0)
        conf_vals.append(float(row[2] or 0.0))
    avg_conf = round((sum(conf_vals) / len(conf_vals)), 3) if conf_vals else 0.0
    needs_update = bool(
        (not_helpful >= 2 and not_helpful >= helpful)
        or unresolved_hits >= 3
        or (len(conf_vals) >= 3 and avg_conf < 0.58)
    )
    return {
        'needs_update': needs_update,
        'helpful': helpful,
        'not_helpful': not_helpful,
        'unresolved_hits': unresolved_hits,
        'avg_confidence': avg_conf,
    }

def _assistant_extract_error_guidance(question_text, q_norm=''):
    raw = str(question_text or '').strip()
    low = raw.lower()
    norm = str(q_norm or '').strip()
    if not raw:
        return None

    def _guidance(answer, steps, confidence=0.86, unresolved=False, next_question='Do you want me to explain the exact fix step by step?', fix_snippet=''):
        return {
            'answer': str(answer or '').strip(),
            'steps': [str(s).strip() for s in (steps or []) if str(s).strip()][:6],
            'confidence': confidence,
            'unresolved': bool(unresolved),
            'next_question': next_question,
            'fix_snippet': str(fix_snippet or '').strip(),
        }

