def ensure_login_security_schema():
    """Best-effort schema guard for login tracking tables/columns."""
    global _LOGIN_SECURITY_SCHEMA_READY
    if _LOGIN_SECURITY_SCHEMA_READY is True:
        return True
    try:
        with db_connection(commit=True) as conn:
            c = conn.cursor()
            db_execute(
                c,
                """CREATE TABLE IF NOT EXISTS login_attempts (
                       id SERIAL PRIMARY KEY,
                       endpoint TEXT NOT NULL,
                       username TEXT NOT NULL,
                       ip_address TEXT NOT NULL,
                       failures INTEGER NOT NULL DEFAULT 0,
                       first_failed_at TIMESTAMP,
                       last_failed_at TIMESTAMP,
                       locked_until TIMESTAMP,
                       UNIQUE(endpoint, username, ip_address)
                   )""",
            )
            db_execute(c, "ALTER TABLE users ADD COLUMN IF NOT EXISTS current_login_at TIMESTAMP")
            db_execute(c, "ALTER TABLE users ADD COLUMN IF NOT EXISTS last_login_at TIMESTAMP")
        _LOGIN_SECURITY_SCHEMA_READY = True
        return True
    except Exception as exc:
        logging.warning("Failed to ensure login security schema: %s", exc)
        return False

def _parse_bool_setting(value, default=False):
    if value is None:
        return default
    raw = str(value).strip().lower()
    if raw in {'1', 'true', 'yes', 'on'}:
        return True
    if raw in {'0', 'false', 'no', 'off'}:
        return False
    return default

def ensure_app_settings_schema():
    if not ensure_extended_features_schema():
        return False
    try:
        with db_connection(commit=True) as conn:
            c = conn.cursor()
            db_execute(
                c,
                """CREATE TABLE IF NOT EXISTS app_settings (
                       setting_key TEXT PRIMARY KEY,
                       setting_value TEXT DEFAULT '',
                       updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                   )""",
            )
        return True
    except Exception as exc:
        logging.warning("App settings schema update failed: %s", exc)
        return False

def get_app_setting(key, default=''):
    if not key:
        return default
    if not ensure_app_settings_schema():
        return default
    with db_connection() as conn:
        c = conn.cursor()
        db_execute(
            c,
            "SELECT setting_value FROM app_settings WHERE setting_key = ? LIMIT 1",
            (key,),
        )
        row = c.fetchone()
    if not row:
        return default
    return row[0] if row[0] is not None else default

def set_app_setting(key, value):
    if not key:
        return 0
    if not ensure_app_settings_schema():
        return 0
    with db_connection(commit=True) as conn:
        c = conn.cursor()
        db_execute(
            c,
            """INSERT INTO app_settings (setting_key, setting_value, updated_at)
               VALUES (?, ?, CURRENT_TIMESTAMP)
               ON CONFLICT(setting_key)
               DO UPDATE SET setting_value = EXCLUDED.setting_value, updated_at = EXCLUDED.updated_at""",
            (key, '' if value is None else str(value)),
        )
        return int(c.rowcount or 0)

def get_email_sending_enabled():
    stored = get_app_setting('email_sending_enabled', '')
    if (stored or '').strip() != '':
        return _parse_bool_setting(stored, default=False)
    return bool(EMAIL_SENDING_ENABLED)

def get_sms_sending_enabled():
    stored = get_app_setting('sms_sending_enabled', '')
    if (stored or '').strip() != '':
        return _parse_bool_setting(stored, default=False)
    return bool(SMS_SENDING_ENABLED)

