def ensure_score_audit_schema():
    global _SCORE_AUDIT_SCHEMA_STATE, _SCORE_AUDIT_SCHEMA_WARNED
    if _SCORE_AUDIT_SCHEMA_STATE is True:
        return True
    allow_runtime_heal = _runtime_schema_heal_allowed()
