@app.errorhandler(500)
def internal_server_error(error):
    """Friendly 500 page with error reference for support."""
    error_uid = ''
    try:
        error_uid = getattr(g, '_last_error_uid', '') or ''
    except Exception:
        error_uid = ''
    if not error_uid:
        try:
            error_uid = log_app_error(error, endpoint=(request.endpoint or ''))
        except Exception:
            error_uid = ''
    role = (session.get('role') or '').strip().lower()
    failing_endpoint = (request.endpoint or '').strip()
    if role == 'super_admin':
        if failing_endpoint in {'super_admin_dashboard', 'view_reports'}:
            back_url = url_for('super_admin_error_logs')
        elif failing_endpoint == 'super_admin_error_logs':
            back_url = url_for('menu')
        else:
            back_url = url_for('super_admin_error_logs')
    elif role == 'school_admin':
        back_url = url_for('school_admin_dashboard')
    elif role == 'teacher':
        back_url = url_for('teacher_dashboard')
    elif role == 'student':
        back_url = url_for('student_dashboard')
    elif role == 'parent':
        back_url = url_for('parent_dashboard')
    else:
        back_url = url_for('home')
    return render_template(
        'shared/error_500.html',
        error_uid=error_uid,
        back_url=back_url,
        role=role,
    ), 500

def _auth_error_render_context(template_name):
    """Build fallback template context for auth routes after an exception."""
    terms_read = False
    try:
        terms_read = (request.args.get('terms_read') == '1') or (request.form.get('agree_terms') == 'on')
    except Exception:
        terms_read = False
    context = {}
    if template_name in {'shared/login.html', 'shared/cbt_login.html'}:
        context['terms_read'] = terms_read
    elif template_name == 'shared/super_admin_2fa.html':
        context['username'] = (
            (session.get('super_admin_2fa_auth_user') or '').strip().lower()
            or (session.get('super_admin_2fa_pending_user') or '').strip().lower()
        )
    return context

def safe_auth_route(template_name):
    """Catch unexpected auth-route failures and return a friendly fallback page."""
    def _decorator(func):
        @wraps(func)
        def _wrapped(*args, **kwargs):
            try:
                return func(*args, **kwargs)
            except HTTPException:
                raise
            except Exception as exc:
                error_uid = ''
                try:
                    error_uid = log_app_error(
                        exc,
                        endpoint=(request.endpoint or func.__name__),
                        extra_meta={'auth_route': func.__name__},
                    )
                except Exception:
                    error_uid = ''
                logging.exception("Auth route failed in %s: %s", func.__name__, exc)
                flash(f'Sign-in temporarily failed. Reference: {error_uid or "ERR-UNKNOWN"}', 'error')
                return render_template(template_name, **_auth_error_render_context(template_name)), 500
        return _wrapped
    return _decorator

