@app.before_request
def enforce_school_operations_toggle():
    """Apply school-level operation lock set by super admin."""
    endpoint = request.endpoint or ''
    if endpoint in {'static', 'login', 'logout', 'home', 'school_access_request'}:
        return None

    role = session.get('role')
    school_id = session.get('school_id')
    if not school_id:
        return None
    try:
        school = get_school(school_id)
    except Exception as exc:
        logging.warning("Skipping operations toggle check due transient DB error: %s", exc)
        return None
    if not school:
        return None
    if safe_int(school.get('operations_enabled', 1), 1):
        # School-level OFF is not active, but teacher-level OFF may still apply.
        if role != 'teacher' or safe_int(school.get('teacher_operations_enabled', 1), 1):
            return None

    teacher_blocked_endpoints = {
        'teacher_attendance',
        'teacher_period_attendance',
        'teacher_allocate_stream',
        'teacher_enter_scores',
        'teacher_enter_subject_scores',
        'teacher_upload_csv',
        'teacher_update_profile',
        'teacher_publish_results',
    }
    school_admin_blocked_endpoints = {
        'school_admin_class_subjects',
        'school_admin_settings',
        'school_admin_add_teacher',
        'school_admin_promote',
        'school_admin_add_students_by_class',
        'school_admin_assign_teacher',
        'school_admin_toggle_operations',
        'school_admin_remove_teacher_assignment',
    }

    if role == 'teacher' and endpoint in teacher_blocked_endpoints:
        if not safe_int(school.get('operations_enabled', 1), 1):
            flash('School operations are OFF by super admin. Teachers are read-only now.', 'error')
        elif not safe_int(school.get('teacher_operations_enabled', 1), 1):
            flash('Teacher operations are OFF by school admin. Teachers are read-only now.', 'error')
        else:
            return None
        return redirect(url_for('teacher_dashboard'))

    school_admin_allowed_when_locked = {
        'school_admin_change_password',
        'privacy_request',
        'report_issue',
        'school_admin_privacy_requests',
        'school_admin_privacy_requests_review',
    }
    if role == 'school_admin' and endpoint not in school_admin_allowed_when_locked and (endpoint in school_admin_blocked_endpoints or request.method == 'POST'):
        flash('School operations are OFF by super admin. School admin is currently in read-only mode.', 'error')
        return redirect(url_for('school_admin_dashboard'))

    return None


@app.before_request
def enforce_school_access_policy():
    """Block app usage for schools that are not currently active/trial-enabled."""
    endpoint = (request.endpoint or '').strip()
    if endpoint in {
        'static',
        'home',
        'login',
        'logout',
        'terms_privacy',
        'help',
        'report_issue',
        'assistant_guide',
        'assistant_feedback',
        'assistant_preferences',
        'assistant_memory_clear',
    }:
        return None

    role = (session.get('role') or '').strip().lower()
    if role in {'', 'super_admin'}:
        return None

    school_ids = []
    if role == 'parent':
        sid = (session.get('school_id') or '').strip()
        if sid:
            school_ids.append(sid)
        for token in (session.get('parent_student_keys') or []):
            raw = str(token or '').strip()
            if '::' not in raw:
                continue
            key_sid = raw.split('::', 1)[0].strip()
            if key_sid and key_sid not in school_ids:
                school_ids.append(key_sid)
    else:
        sid = (session.get('school_id') or '').strip()
        if sid:
            school_ids.append(sid)

    if not school_ids:
        return None

    blocked_message = 'School access is restricted. Contact super admin.'
    for sid in school_ids:
        try:
            school = get_school(sid) or {}
        except Exception as exc:
            logging.warning("Skipping school access policy check for %s due lookup error: %s", sid, exc)
            continue
        access_state = build_school_access_state(school)
        if access_state.get('is_allowed', False):
            return None
        blocked_message = access_state.get('message') or blocked_message

    session.clear()
    flash(blocked_message, 'error')
    return redirect(url_for('login'))


