@app.route('/school-admin/add-teacher', methods=['POST'])
def school_admin_add_teacher():
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    
    school_id = session.get('school_id')
    fallback_redirect = request.referrer or url_for('school_admin_dashboard')
    username = request.form.get('username', '').strip().lower()
    firstname = normalize_person_name(request.form.get('firstname', '').strip())
    lastname = normalize_person_name(request.form.get('lastname', '').strip())
    gender = normalize_teacher_gender(request.form.get('gender', '').strip())
    phone = (request.form.get('phone', '') or '').strip()
    send_credentials = (request.form.get('send_credentials', '') or '').strip() in {'1', 'true', 'yes', 'on'}
    password = request.form.get('password', '').strip()
    
    if username and firstname:
        try:
            if not is_valid_email(username):
                flash('Teacher username must be a valid email address.', 'error')
                return redirect(fallback_redirect)
            temp_password = ''
            manual_password = bool(password)
            if not password:
                temp_password = generate_temp_password()
                password = temp_password
            if gender not in {'male', 'female', 'other'}:
                flash('Teacher gender is required.', 'error')
                return redirect(fallback_redirect)
            existing_user = get_user(username)
            if existing_user:
                existing_role = (existing_user.get('role') or '').strip().lower()
                existing_school = (existing_user.get('school_id') or '').strip()
                if not (existing_role == 'teacher' and existing_school == school_id):
                    flash('This username already belongs to another account/school. Choose a different email.', 'error')
                    return redirect(fallback_redirect)
            if not existing_user:
                try:
                    ensure_school_plan_capacity(school_id, add_students=0, add_teachers=1)
                except Exception as exc:
                    flash(str(exc), 'error')
                    return redirect(fallback_redirect)
            password_hash = hash_password(password)
            upsert_user(username, password_hash, 'teacher', school_id)
            save_teacher(
                school_id,
                username,
                firstname,
                lastname,
                [],
                phone=phone,
                gender=gender,
            )
            flash(f'Teacher added successfully. Username: {username}', 'success')
            if send_credentials and (temp_password or manual_password):
                school_name = (get_school(school_id) or {}).get('school_name', 'your school')
                login_url = url_for('login', _external=True)
                password_label = 'Temporary password' if temp_password else 'Password'
                subject = f"Teacher Account Created - {school_name}"
                body = (
                    f"Hello {firstname or 'Teacher'},\n\n"
                    f"Your teacher account has been created for {school_name}.\n"
                    f"Username: {username}\n"
                    f"{password_label}: {password}\n\n"
                    f"Login here: {login_url}\n"
                    "Please log in and change your password immediately.\n\n"
                    "If you did not expect this, contact your school admin."
                )
                email_result = send_plain_email_message(subject, body, [username])
                sms_result = {'sent_sms': 0, 'errors': []}
                if phone:
                    sms_body = (
                        f"{school_name} teacher account created.\n"
                        f"Username: {username}\n"
                        f"{password_label}: {password}\n"
                        f"Login: {login_url}\n"
                        "Please change your password after login."
                    )
                    sms_result = send_bulk_sms_messages(
                        [phone],
                        sms_body,
                        school_name=school_name,
                        context='teacher_temp_password',
                        school_id=school_id,
                        audience_role='teacher',
                    )
                    if sms_result.get('errors'):
                        flash(f"SMS issue: {sms_result.get('errors')[0]}", 'warning')
                email_sent = bool(email_result.get('sent'))
                sms_sent = bool(sms_result.get('sent_sms'))
                if email_sent:
                    flash(f'{password_label} emailed to {username}.', 'success')
                if sms_sent:
                    flash(f'{password_label} sent by SMS.', 'success')
                if not email_sent and not sms_sent:
                    err = (email_result.get('errors') or ['Email send failed.'])[0]
                    if temp_password:
                        flash(f'Email failed ({err}). Share this temp password with the teacher: {temp_password}', 'warning')
                    else:
                        flash(f'Email failed ({err}). Share the password you set with the teacher.', 'warning')
            elif not send_credentials:
                if temp_password:
                    flash(f'Credentials not sent. Share this temp password with the teacher: {temp_password}', 'warning')
                elif manual_password:
                    flash('Credentials not sent. Remember to share the password you set with the teacher.', 'warning')
        except Exception as e:
            flash(f'Error adding teacher: {str(e)}', 'error')
    
    return redirect(fallback_redirect)

@app.route('/school-admin/promote-students', methods=['GET', 'POST'])
def school_admin_promote():
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    
    school_id = session.get('school_id')
    school = get_school(school_id) or {}
    current_term = get_current_term(school)
    
    if request.method == 'POST':
        from_class = canonicalize_classname(request.form.get('from_class', '').strip())
        to_class = canonicalize_classname(request.form.get('to_class', '').strip())
        from_level = get_class_level(from_class)
        from_no = _extract_class_number(from_class)
        auto_ss3 = from_level == 'ss' and from_no == 3
        action_by_student = {}
        for key, value in request.form.items():
            if key.startswith('action_'):
                student_id = key.replace('action_', '', 1)
                action_by_student[student_id] = value

        if from_class and to_class:
            adjusted_to = apply_promotion_arm_target(from_class, to_class, school=school)
            if adjusted_to != to_class:
                to_class = adjusted_to
                flash(f'Class arm preserved: target class adjusted to {to_class}.', 'info')
            if from_class == to_class and not auto_ss3:
                flash('Current class and promote-to class cannot be the same.', 'error')
                return redirect(url_for('school_admin_promote', from_class=from_class))
            if not auto_ss3 and not is_valid_promotion_target(from_class, to_class):
                expected = next_class_in_sequence(from_class)
                if expected:
                    flash(f'Invalid promotion path. {from_class} can only move to {expected}.', 'error')
                else:
                    flash(f'Invalid source class "{from_class}" for promotion.', 'error')
                return redirect(url_for('school_admin_promote', from_class=from_class))
            if auto_ss3:
                flash('SS3 promote actions are auto-mapped to Graduated.', 'info')
            promote_students(
                school_id,
                from_class,
                to_class,
                action_by_student,
                term=current_term,
                academic_year=(school.get('academic_year', '') or ''),
                changed_by=(session.get('user_id') or ''),
            )
            record_admin_action_audit(
                school_id,
                'promote_students',
                target_scope=f'{from_class}->{to_class}',
                payload={
                    'term': current_term,
                    'academic_year': (school.get('academic_year', '') or ''),
                    'students_selected': len(action_by_student),
                },
            )
            flash('Class transitions applied successfully.', 'success')
        
        return redirect(url_for('school_admin_dashboard'))
    
    students = load_students(school_id, term_filter=current_term)
    classes = list(set(s['classname'] for s in students.values()))
    selected_class = request.args.get('from_class', '').strip()
    selected_class_key = canonicalize_classname(selected_class) if selected_class else ''
    selected_class_display = next(
        (cls for cls in classes if canonicalize_classname(cls) == selected_class_key),
        selected_class
    )
    class_students = {
        sid: data for sid, data in students.items()
        if not selected_class or canonicalize_classname(data.get('classname', '')) == selected_class_key
    }
    base_to_classes = [
        'JSS1', 'JSS2', 'JSS3',
        'SS1', 'SS2', 'SS3',
        'GRADUATED',
    ]
    suggested_next_class = next_class_in_sequence(selected_class_display or selected_class) if selected_class else ''
    to_class_options = _dedupe_keep_order(
        [x for x in (base_to_classes + sorted(classes) + ([suggested_next_class] if suggested_next_class else [])) if x]
    )
    return render_template(
        'school/promote_students.html',
        classes=sorted(classes),
        to_class_options=to_class_options,
        suggested_next_class=suggested_next_class,
        students=class_students,
        selected_class=selected_class_display,
        current_term=current_term
    )

@app.route('/school-admin/promotion-audit')
def school_admin_promotion_audit():
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    school_id = session.get('school_id')
    ensure_extended_features_schema()
    classname = (request.args.get('classname', '') or '').strip()
    action = (request.args.get('action', '') or '').strip().lower()
    where = ['school_id = ?']
    params = [school_id]
    if classname:
        where.append('LOWER(from_class) = LOWER(?)')
        params.append(classname)
    if action in {'promote', 'repeat', 'remove'}:
        where.append('action = ?')
        params.append(action)
    with db_connection() as conn:
        c = conn.cursor()
        db_execute(
            c,
            f"""SELECT student_id, student_name, from_class, to_class, action, term, academic_year, changed_by, created_at
                FROM promotion_audit_logs
                WHERE {' AND '.join(where)}
                ORDER BY created_at DESC
                LIMIT 500""",
            tuple(params),
        )
        rows = c.fetchall() or []
    logs = [{
        'student_id': r[0] or '',
        'student_name': r[1] or '',
        'from_class': r[2] or '',
        'to_class': r[3] or '',
        'action': r[4] or '',
        'term': r[5] or '',
        'academic_year': r[6] or '',
        'changed_by': r[7] or '',
        'created_at': format_timestamp(r[8]),
    } for r in rows]
    classes = sorted(set((item.get('from_class') or '') for item in logs if item.get('from_class')))
    return render_template('school/school_admin_promotion_audit.html', logs=logs, classes=classes, selected_class=classname, selected_action=action)

@app.route('/school-admin/timetable', methods=['GET', 'POST'])
def school_admin_timetable():
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    school_id = session.get('school_id')
    ensure_extended_features_schema()
    school = get_school(school_id) or {}
    current_term = get_current_term(school)
    current_year = (school or {}).get('academic_year', '')
    assignments = get_class_assignments(school_id)
    classes = filter_secondary_classnames(
        set(get_student_count_by_class(school_id).keys())
        | {a.get('classname', '') for a in assignments if a.get('classname')}
    )
    teachers = get_teachers(school_id) or {}
    subject_assignment_rows = get_teacher_subject_assignments(
        school_id,
        term=current_term,
        academic_year=current_year,
    )
    subject_teacher_by_key = {}
    for row in subject_assignment_rows:
        cls_key = canonicalize_classname(row.get('classname', '')).strip().lower()
        subj_key = normalize_subject_name(row.get('subject', '')).strip().lower()
        teacher_id_key = (row.get('teacher_id', '') or '').strip()
        if cls_key and subj_key and teacher_id_key:
            subject_teacher_by_key[(cls_key, subj_key)] = teacher_id_key
    if request.method == 'POST':
        action = (request.form.get('action', '') or '').strip().lower()
        actor_user_id = (session.get('user_id') or '').strip()
        affected_notification_targets = set()

        def _slot_lookup_row(cursor, cls_name, day_num, period_name):
            db_execute(
                cursor,
                """SELECT id, classname, day_of_week, period_label, subject, teacher_id, start_time, end_time, room
                   FROM class_timetables
                   WHERE school_id = ? AND LOWER(classname) = LOWER(?) AND day_of_week = ? AND LOWER(period_label) = LOWER(?)
                   LIMIT 1""",
                (school_id, canonicalize_classname(cls_name), int(day_num or 0), (period_name or '').strip()),
            )
            r = cursor.fetchone()
            if not r:
                return {}
            return {
                'id': int(r[0] or 0),
                'classname': r[1] or '',
                'day_of_week': int(r[2] or 0),
                'period_label': r[3] or '',
                'subject': r[4] or '',
                'teacher_id': r[5] or '',
                'start_time': r[6] or '',
                'end_time': r[7] or '',
                'room': r[8] or '',
            }

        try:
            with db_connection(commit=True) as conn:
                c = conn.cursor()
                if action == 'delete':
                    row_id = int(request.form.get('row_id', 0) or 0)
                    db_execute(
                        c,
                        """SELECT id, classname, day_of_week, period_label, subject, teacher_id, start_time, end_time, room
                           FROM class_timetables
                           WHERE school_id = ? AND id = ?
                           LIMIT 1""",
                        (school_id, row_id),
                    )
                    existing = c.fetchone()
                    if not existing:
                        raise ValueError('Timetable row not found.')
                    before_row = {
                        'id': int(existing[0] or 0),
                        'classname': existing[1] or '',
                        'day_of_week': int(existing[2] or 0),
                        'period_label': existing[3] or '',
                        'subject': existing[4] or '',
                        'teacher_id': existing[5] or '',
                        'start_time': existing[6] or '',
                        'end_time': existing[7] or '',
                        'room': existing[8] or '',
                    }
                    db_execute(c, "DELETE FROM class_timetables WHERE school_id = ? AND id = ?", (school_id, row_id))
                    log_timetable_change_with_cursor(
                        c,
                        school_id,
                        action='delete',
                        row_before=before_row,
                        row_after={},
                        changed_by=actor_user_id,
                    )
                    if before_row.get('classname') and before_row.get('subject'):
                        affected_notification_targets.add((before_row.get('classname', ''), before_row.get('subject', '')))
                    flash('Timetable row removed.', 'success')
                elif action == 'restore_history':
                    history_id = int(request.form.get('history_id', 0) or 0)
                    history = get_timetable_change_log(school_id, history_id)
                    if not history:
                        raise ValueError('History entry not found.')
                    source_payload = history.get('before') or history.get('after') or {}
                    classname = canonicalize_classname(source_payload.get('classname', ''))
                    day_of_week = int(source_payload.get('day_of_week') or 0)
                    period_label = (source_payload.get('period_label') or '').strip()
                    subject = normalize_subject_name(source_payload.get('subject', ''))
                    start_time = (source_payload.get('start_time') or '').strip()
                    end_time = (source_payload.get('end_time') or '').strip()
                    room = (source_payload.get('room') or '').strip()
                    if not classname or not period_label or not subject or day_of_week < 1 or day_of_week > 7:
                        raise ValueError('History entry is incomplete and cannot be restored.')
                    teacher_id = subject_teacher_by_key.get((classname.strip().lower(), subject.strip().lower()), '')
                    if not teacher_id:
                        raise ValueError(
                            f'No teacher subject assignment found for "{subject}" in class "{classname}" '
                            f'for {current_term} {current_year}.'
                        )
                    existing_before = _slot_lookup_row(c, classname, day_of_week, period_label)
                    existing_id = int(existing_before.get('id') or 0)
                    conflicts = find_timetable_time_conflicts(
                        school_id,
                        classname,
                        day_of_week,
                        start_time,
                        end_time,
                        ignore_row_id=existing_id,
                    )
                    if conflicts:
                        raise ValueError(f"Cannot restore due to time conflict: {conflicts[0].get('message', 'Overlap detected')}")
                    db_execute(
                        c,
                        """INSERT INTO class_timetables
                           (school_id, classname, day_of_week, period_label, subject, teacher_id, start_time, end_time, room, updated_at)
                           VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
                           ON CONFLICT (school_id, classname, day_of_week, period_label) DO UPDATE SET
                             subject = EXCLUDED.subject,
                             teacher_id = EXCLUDED.teacher_id,
                             start_time = EXCLUDED.start_time,
                             end_time = EXCLUDED.end_time,
                             room = EXCLUDED.room,
                             updated_at = CURRENT_TIMESTAMP""",
                        (school_id, classname, day_of_week, period_label, subject, teacher_id, start_time, end_time, room),
                    )
                    after_row = {
                        'classname': classname,
                        'day_of_week': day_of_week,
                        'period_label': period_label,
                        'subject': subject,
                        'teacher_id': teacher_id,
                        'start_time': start_time,
                        'end_time': end_time,
                        'room': room,
                    }
                    log_timetable_change_with_cursor(
                        c,
                        school_id,
                        action='restore',
                        row_before=existing_before,
                        row_after=after_row,
                        changed_by=actor_user_id,
                    )
                    affected_notification_targets.add((classname, subject))
                    flash('Timetable version restored.', 'success')
                elif action in {'import', 'upload', 'import_csv'}:
                    upload = request.files.get('timetable_file')
                    if not upload or not (upload.filename or '').strip():
                        raise ValueError('Choose a CSV file to import.')
                    raw = upload.read() or b''
                    if not raw:
                        raise ValueError('Uploaded timetable file is empty.')
                    try:
                        text = raw.decode('utf-8-sig')
                    except Exception:
                        text = raw.decode('utf-8', errors='replace')
                    reader = csv.DictReader(StringIO(text))
                    if not reader.fieldnames:
                        raise ValueError('CSV header is missing.')
                    day_map = {str(int(d)): int(d) for d, _ in DAY_OF_WEEK_OPTIONS}
                    for d, name in DAY_OF_WEEK_OPTIONS:
                        key = (name or '').strip().lower()
                        if key:
                            day_map[key] = int(d)
                            day_map[key[:3]] = int(d)
                    imported = 0
                    row_errors = []
                    max_rows = 2000
                    for idx, row in enumerate(reader, start=2):
                        if imported >= max_rows:
                            row_errors.append(f'Row {idx}: import limit ({max_rows}) reached.')
                            break
                        classname = canonicalize_classname((row.get('classname', '') or row.get('class', '')).strip())
                        day_raw = (row.get('day_of_week', '') or row.get('day', '')).strip().lower()
                        period_label = (row.get('period_label', '') or row.get('period', '')).strip()
                        subject = normalize_subject_name((row.get('subject', '') or '').strip())
                        start_time = (row.get('start_time', '') or row.get('start', '')).strip()
                        end_time = (row.get('end_time', '') or row.get('end', '')).strip()
                        room = (row.get('room', '') or '').strip()
                        if not classname or not day_raw or not period_label or not subject:
                            row_errors.append(f'Row {idx}: classname/day/period_label/subject are required.')
                            continue
                        if not is_secondary_classname(classname):
                            row_errors.append(f'Row {idx}: only secondary classes are supported (JSS/SS).')
                            continue
                        day_of_week = day_map.get(day_raw)
                        if day_of_week is None:
                            row_errors.append(f'Row {idx}: day "{day_raw}" is invalid.')
                            continue
                        if start_time and not re.fullmatch(r'\d{2}:\d{2}', start_time):
                            row_errors.append(f'Row {idx}: start_time must be HH:MM.')
                            continue
                        if end_time and not re.fullmatch(r'\d{2}:\d{2}', end_time):
                            row_errors.append(f'Row {idx}: end_time must be HH:MM.')
                            continue
                        teacher_id = subject_teacher_by_key.get((classname.strip().lower(), subject.strip().lower()), '')
                        if not teacher_id:
                            row_errors.append(
                                f'Row {idx}: no teacher subject assignment found for "{subject}" in class "{classname}" ({current_term}, {current_year}).'
                            )
                            continue
                        existing_before = _slot_lookup_row(c, classname, day_of_week, period_label)
                        existing_id = int(existing_before.get('id') or 0)
                        conflicts = find_timetable_time_conflicts(
                            school_id,
                            classname,
                            day_of_week,
                            start_time,
                            end_time,
                            ignore_row_id=existing_id,
                        )
                        if conflicts:
                            row_errors.append(f'Row {idx}: {conflicts[0].get("message", "Time overlap detected.")}')
                            continue
                        db_execute(
                            c,
                            """INSERT INTO class_timetables
                               (school_id, classname, day_of_week, period_label, subject, teacher_id, start_time, end_time, room, updated_at)
                               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
                               ON CONFLICT (school_id, classname, day_of_week, period_label) DO UPDATE SET
                                 subject = EXCLUDED.subject,
                                 teacher_id = EXCLUDED.teacher_id,
                                 start_time = EXCLUDED.start_time,
                                 end_time = EXCLUDED.end_time,
                                 room = EXCLUDED.room,
                                 updated_at = CURRENT_TIMESTAMP""",
                            (school_id, classname, day_of_week, period_label, subject, teacher_id, start_time, end_time, room),
                        )
                        after_row = {
                            'classname': classname,
                            'day_of_week': day_of_week,
                            'period_label': period_label,
                            'subject': subject,
                            'teacher_id': teacher_id,
                            'start_time': start_time,
                            'end_time': end_time,
                            'room': room,
                        }
                        log_timetable_change_with_cursor(
                            c,
                            school_id,
                            action='update' if existing_before else 'create',
                            row_before=existing_before,
                            row_after=after_row,
                            changed_by=actor_user_id,
                        )
                        affected_notification_targets.add((classname, subject))
                        imported += 1
                    if imported:
                        flash(f'Timetable import completed. {imported} row(s) processed.', 'success')
                    if row_errors:
                        preview = '; '.join(row_errors[:4])
                        extra = f' (+{len(row_errors) - 4} more)' if len(row_errors) > 4 else ''
                        flash(f'Import warnings: {preview}{extra}', 'error')
                    if not imported and row_errors:
                        raise ValueError('No timetable row was imported. Fix CSV errors and retry.')
                else:
                    classname = canonicalize_classname(request.form.get('classname', ''))
                    day_of_week = int(request.form.get('day_of_week', 1) or 1)
                    period_label = (request.form.get('period_label', '') or '').strip()
                    subject = normalize_subject_name(request.form.get('subject', ''))
                    start_time = (request.form.get('start_time', '') or '').strip()
                    end_time = (request.form.get('end_time', '') or '').strip()
                    room = (request.form.get('room', '') or '').strip()
                    if not classname or not period_label or not subject:
                        raise ValueError('Class, period label, and subject are required.')
                    if not is_secondary_classname(classname):
                        raise ValueError('Only secondary classes are supported (JSS/SS).')
                    if day_of_week < 1 or day_of_week > 7:
                        raise ValueError('Day must be between 1 and 7.')
                    if start_time and not re.fullmatch(r'\d{2}:\d{2}', start_time):
                        raise ValueError('Start time must be HH:MM.')
                    if end_time and not re.fullmatch(r'\d{2}:\d{2}', end_time):
                        raise ValueError('End time must be HH:MM.')
                    teacher_id = subject_teacher_by_key.get((classname.strip().lower(), subject.strip().lower()), '')
                    if not teacher_id:
                        raise ValueError(
                            f'No teacher subject assignment found for "{subject}" in class "{classname}" '
                            f'for {current_term} {current_year}. Assign subject teacher first on dashboard.'
                        )
                    existing_before = _slot_lookup_row(c, classname, day_of_week, period_label)
                    existing_id = int(existing_before.get('id') or 0)
                    conflicts = find_timetable_time_conflicts(
                        school_id,
                        classname,
                        day_of_week,
                        start_time,
                        end_time,
                        ignore_row_id=existing_id,
                    )
                    if conflicts:
                        raise ValueError(f"Cannot save due to time conflict: {conflicts[0].get('message', 'Overlap detected')}")
                    db_execute(
                        c,
                        """INSERT INTO class_timetables
                           (school_id, classname, day_of_week, period_label, subject, teacher_id, start_time, end_time, room, updated_at)
                           VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
                           ON CONFLICT (school_id, classname, day_of_week, period_label) DO UPDATE SET
                             subject = EXCLUDED.subject,
                             teacher_id = EXCLUDED.teacher_id,
                             start_time = EXCLUDED.start_time,
                             end_time = EXCLUDED.end_time,
                             room = EXCLUDED.room,
                             updated_at = CURRENT_TIMESTAMP""",
                        (school_id, classname, day_of_week, period_label, subject, teacher_id, start_time, end_time, room),
                    )
                    after_row = {
                        'classname': classname,
                        'day_of_week': day_of_week,
                        'period_label': period_label,
                        'subject': subject,
                        'teacher_id': teacher_id,
                        'start_time': start_time,
                        'end_time': end_time,
                        'room': room,
                    }
                    log_timetable_change_with_cursor(
                        c,
                        school_id,
                        action='update' if existing_before else 'create',
                        row_before=existing_before,
                        row_after=after_row,
                        changed_by=actor_user_id,
                    )
                    affected_notification_targets.add((classname, subject))
                    flash('Timetable saved.', 'success')
            # Notify affected parents using parent-visible student messages.
            for cls, subj in sorted(affected_notification_targets):
                if not cls:
                    continue
                scoped_classes = related_classnames_for_class_arm_mode(school_id, cls, school=school) or [cls]
                for target_class in scoped_classes:
                    try:
                        create_student_message(
                            school_id=school_id,
                            title='Timetable Updated',
                            message=(
                                f'Timetable was updated for {target_class}'
                                + (f' ({subj})' if subj else '')
                                + '. Open Parent Timetable to review latest periods.'
                            ),
                            target_classname=target_class,
                            target_subject=subj or '',
                            message_context='timetable',
                            created_by=actor_user_id,
                        )
                    except Exception:
                        # Keep timetable save resilient even if notification creation fails.
                        pass
        except Exception as exc:
            flash(f'Failed to save timetable: {exc}', 'error')
        return redirect(url_for('school_admin_timetable'))

    selected_class = (request.args.get('classname', '') or '').strip()
    rows = get_school_timetable_rows(school_id, classname=selected_class)
    for row in rows:
        tid = (row.get('teacher_id') or '').strip()
        profile = teachers.get(tid, {}) if tid else {}
        if profile:
            row['teacher_label'] = f"{(profile.get('firstname', '') or '').strip()} {(profile.get('lastname', '') or '').strip()} ({tid})".strip()
        else:
            row['teacher_label'] = tid or '-'
    class_subject_teacher_map = {}
    for row in subject_assignment_rows:
        cls = canonicalize_classname(row.get('classname', ''))
        subj = normalize_subject_name(row.get('subject', ''))
        tid = (row.get('teacher_id', '') or '').strip()
        if not cls or not subj or not tid:
            continue
        teacher_profile = teachers.get(tid, {}) or {}
        teacher_name = f"{(teacher_profile.get('firstname', '') or '').strip()} {(teacher_profile.get('lastname', '') or '').strip()}".strip()
        class_subject_teacher_map.setdefault(cls, {})[subj] = {
            'teacher_id': tid,
            'teacher_name': teacher_name or tid,
        }
    history_rows = list_timetable_change_logs(school_id, classname=selected_class, limit=120)
    return render_template(
        'school/school_admin_timetable.html',
        school=school,
        classes=classes,
        teachers=teachers,
        day_options=DAY_OF_WEEK_OPTIONS,
        rows=rows,
        selected_class=selected_class,
        class_subject_teacher_map=class_subject_teacher_map,
        history_rows=history_rows,
    )

