@app.route('/school-admin/reports/export/<kind>')
def school_admin_reports_export(kind):
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    school_id = session.get('school_id')
    school = get_school(school_id) or {}
    term = (request.args.get('term', '') or '').strip() or get_current_term(school)
    academic_year = (request.args.get('academic_year', '') or '').strip() or (school.get('academic_year', '') or '')
    kind = (kind or '').strip().lower()
    output = StringIO()
    writer = csv.writer(output)
    if kind == 'term_summary':
        writer.writerow(['classname', 'student_count', 'avg_average_marks'])
        with db_connection() as conn:
            c = conn.cursor()
            db_execute(
                c,
                """SELECT classname, COUNT(*), AVG(average_marks)
                   FROM published_student_results
                   WHERE school_id = ? AND term = ? AND academic_year = ?
                   GROUP BY classname
                   ORDER BY classname""",
                (school_id, term, academic_year),
            )
            rows = c.fetchall() or []
        if not rows:
            with db_connection() as conn:
                c = conn.cursor()
                db_execute(
                    c,
                    """SELECT classname, COUNT(*)
                       FROM students
                       WHERE school_id = ? AND term = ?
                       GROUP BY classname
                       ORDER BY classname""",
                    (school_id, term),
                )
                rows = [(r[0], r[1], None) for r in (c.fetchall() or [])]
        for row in rows:
            writer.writerow([row[0] or '', row[1] or 0, f"{row[2]:.2f}" if row[2] is not None else ''])
        filename = f'term_summary_{term}_{academic_year}.csv'
    elif kind == 'attendance_summary':
        writer.writerow(['classname', 'present_count', 'absent_count', 'total'])
        counts = {}
        with db_connection() as conn:
            c = conn.cursor()
            db_execute(
                c,
                """SELECT classname, status
                   FROM period_attendance
                   WHERE school_id = ? AND term = ? AND academic_year = ?""",
                (school_id, term, academic_year),
            )
            rows = c.fetchall() or []
        for cls, status in rows:
            key = cls or ''
            counts.setdefault(key, {'present': 0, 'absent': 0, 'total': 0})
            if (status or '').strip().lower() == 'present':
                counts[key]['present'] += 1
            elif (status or '').strip().lower() == 'absent':
                counts[key]['absent'] += 1
            counts[key]['total'] += 1
        for cls in sorted(counts.keys(), key=lambda x: str(x).lower()):
            row = counts[cls]
            writer.writerow([cls, row['present'], row['absent'], row['total']])
        filename = f'attendance_summary_{term}_{academic_year}.csv'
    elif kind == 'subject_performance':
        writer.writerow(['subject', 'student_count', 'avg_score'])
        totals = {}
        counts = {}
        with db_connection() as conn:
            c = conn.cursor()
            db_execute(
                c,
                """SELECT scores, subjects
                   FROM published_student_results
                   WHERE school_id = ? AND term = ? AND academic_year = ?""",
                (school_id, term, academic_year),
            )
            rows = c.fetchall() or []
        for scores_str, subjects_str in rows:
            scores_map = _safe_json_object(scores_str)
            subjects = normalize_subjects_list(_safe_json_rows(subjects_str))
            for subject in subjects:
                block = get_subject_score_block(scores_map, subject)
                if not isinstance(block, dict) or not block:
                    continue
                score = subject_overall_mark(block)
                key = normalize_subject_name(subject)
                totals[key] = totals.get(key, 0.0) + float(score or 0)
                counts[key] = counts.get(key, 0) + 1
        for subject in sorted(totals.keys(), key=lambda x: x.lower()):
            total = totals.get(subject, 0.0)
            count = counts.get(subject, 0)
            avg = (total / count) if count else 0
            writer.writerow([subject, count, f"{avg:.2f}"])
        filename = f'subject_performance_{term}_{academic_year}.csv'
    else:
        flash('Invalid report export.', 'error')
        return redirect(url_for('school_admin_reports'))
    return Response(
        output.getvalue(),
        mimetype='text/csv',
        headers={'Content-Disposition': f'attachment; filename={filename}'},
    )

@app.route('/school-admin/export/<target>')
def school_admin_export_target(target):
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    school_id = session.get('school_id')
    target_key = (target or '').strip().lower()
    mapping = {
        'students': ('students', ['student_id', 'firstname', 'email', 'date_of_birth', 'gender', 'classname', 'first_year_class', 'term', 'stream', 'number_of_subject', 'subjects', 'scores', 'promoted', 'parent_phone', 'parent_phone_2']),
        'teachers': ('teachers', ['user_id', 'firstname', 'lastname', 'phone', 'gender', 'assigned_classes', 'subjects_taught']),
        'class_assignments': ('class_assignments', ['teacher_id', 'classname', 'term', 'academic_year']),
    }
    if target_key not in mapping:
        flash('Invalid export target.', 'error')
        return redirect(url_for('school_admin_bulk_tools'))
    table_name, cols = mapping[target_key]
    with db_connection() as conn:
        c = conn.cursor()
        db_execute(c, f"SELECT {', '.join(cols)} FROM {table_name} WHERE school_id = ? ORDER BY 1", (school_id,))
        rows = c.fetchall() or []
    output = StringIO()
    writer = csv.writer(output)
    writer.writerow(cols)
    for row in rows:
        writer.writerow([row[idx] if row[idx] is not None else '' for idx in range(len(cols))])
    return Response(
        output.getvalue(),
        mimetype='text/csv',
        headers={'Content-Disposition': f'attachment; filename={target_key}_{school_id}.csv'},
    )

@app.route('/school-admin/import/<target>', methods=['POST'])
def school_admin_import_target(target):
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    school_id = session.get('school_id')
    target_key = (target or '').strip().lower()
    dry_run = (request.form.get('dry_run', '') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
    file = request.files.get('file')
    if not file or not (file.filename or '').lower().endswith('.csv'):
        flash('Upload a valid CSV file.', 'error')
        return redirect(url_for('school_admin_bulk_tools'))
    try:
        text = file.read().decode('utf-8-sig')
        reader = csv.DictReader(StringIO(text))
        if not reader.fieldnames:
            raise ValueError('CSV is empty or missing headers.')
        rows = list(reader)
    except Exception as exc:
        flash(f'Failed to parse CSV: {exc}', 'error')
        return redirect(url_for('school_admin_bulk_tools'))

    headers = {str(h or '').strip().lower(): h for h in (reader.fieldnames or []) if str(h or '').strip()}
    required_by_target = {
        'students': ['firstname', 'classname', 'term'],
        'teachers': ['user_id', 'firstname', 'lastname'],
        'class_assignments': ['teacher_id', 'classname', 'term', 'academic_year'],
    }
    if target_key not in required_by_target:
        flash('Invalid import target.', 'error')
        return redirect(url_for('school_admin_bulk_tools'))
    missing_headers = [h for h in required_by_target[target_key] if h not in headers]
    if missing_headers:
        flash(f'Missing required CSV columns: {", ".join(missing_headers)}', 'error')
        return redirect(url_for('school_admin_bulk_tools'))

    error_rows = []
    processed = 0
    imported = 0
    def add_error(row_num, row_obj, message):
        out = {k: (row_obj.get(k, '') if isinstance(row_obj, dict) else '') for k in (reader.fieldnames or [])}
        out['Error'] = message
        out['RowNumber'] = row_num
        error_rows.append(out)

    try:
        if target_key == 'students':
            school = get_school(school_id) or {}
            class_config_cache = {}
            next_index_by_class = {}
            batch_student_ids = set()
            for idx, row in enumerate(rows, start=2):
                classname = canonicalize_classname(row.get('classname', ''))
                term = (row.get('term', '') or '').strip()
                firstname = normalize_person_name(row.get('firstname', '') or row.get('student_name', '') or row.get('name', ''))
                lastname = normalize_person_name(row.get('lastname', '') or row.get('surname', ''))
                full_name = (f'{firstname} {lastname}'.strip() if lastname else firstname).strip()
                email = (row.get('email', '') or row.get('student_email', '') or '').strip().lower()
                if not firstname:
                    add_error(idx, row, 'firstname is required.')
                    continue
                if email and not is_valid_email(email):
                    add_error(idx, row, 'email must be a valid address (or blank).')
                    continue
                if term not in {'First Term', 'Second Term', 'Third Term'}:
                    add_error(idx, row, 'term must be First Term, Second Term, or Third Term.')
                    continue
                if not classname:
                    add_error(idx, row, 'classname is required.')
                    continue
                if not is_secondary_classname(classname):
                    add_error(idx, row, 'classname must be a secondary class (JSS/SS).')
                    continue
                first_year_class = canonicalize_classname(row.get('first_year_class', row.get('classname', '')))
                if not is_secondary_classname(first_year_class):
                    add_error(idx, row, 'first_year_class must be a secondary class (JSS/SS).')
                    continue
                sid_raw = (row.get('student_id', '') or '').strip()
                sid = ''
                if sid_raw:
                    sid = with_school_suffix_manual_id(sid_raw, school_id)
                    if not is_valid_manual_student_id(sid):
                        add_error(idx, row, f'student_id "{sid_raw}" is invalid.')
                        continue
                else:
                    next_index = next_index_by_class.get(first_year_class)
                    if not next_index:
                        next_index = get_next_student_index_for_class(school_id, first_year_class)
                    candidate = generate_student_id(school_id, next_index, first_year_class)
                    while (
                        load_student(school_id, candidate)
                        or candidate.lower() in batch_student_ids
                        or bool(get_user(candidate))
                    ):
                        next_index += 1
                        candidate = generate_student_id(school_id, next_index, first_year_class)
                    sid = candidate
                    next_index_by_class[first_year_class] = next_index + 1
                processed += 1
                if sid.lower() in batch_student_ids:
                    add_error(idx, row, f'student_id "{sid}" is duplicated in this import batch.')
                    continue
                batch_student_ids.add(sid.lower())
                existing_user = get_user(sid)
                if existing_user:
                    existing_role = (existing_user.get('role') or '').strip().lower()
                    existing_school = (existing_user.get('school_id') or '').strip()
                    if not (existing_role == 'student' and existing_school == school_id):
                        add_error(idx, row, f'student_id "{sid}" already belongs to another account/school.')
                        continue
                promoted_raw = (row.get('promoted', '') or '').strip().lower()
                if promoted_raw not in {'', '0', '1', 'true', 'false', 'yes', 'no'}:
                    add_error(idx, row, 'promoted must be 0/1/true/false/yes/no.')
                    continue

                class_config = class_config_cache.get(classname)
                if class_config is None:
                    class_config = get_class_subject_config(school_id, classname)
                    class_config_cache[classname] = class_config
                if not class_config:
                    add_error(idx, row, f'No class subject configuration found for {classname}.')
                    continue

                input_stream = (row.get('stream', '') or '').strip()
                if class_uses_stream_for_school(school, classname):
                    if input_stream:
                        normalized_stream, stream_error = normalize_stream_for_class(
                            classname, input_stream, school=school
                        )
                        if stream_error:
                            add_error(idx, row, stream_error)
                            continue
                        subjects, final_stream, subject_error = build_subjects_from_config(
                            classname=classname,
                            stream=normalized_stream,
                            config=class_config,
                            selected_optional_subjects=[],
                            school=school,
                        )
                        if subject_error:
                            add_error(idx, row, subject_error)
                            continue
                    else:
                        # Allow import without stream allocation for SS classes.
                        subjects = _dedupe_keep_order(class_config.get('core_subjects', []) or [])
                        final_stream = 'N/A'
                else:
                    subjects, final_stream, subject_error = build_subjects_from_config(
                        classname=classname,
                        stream='N/A',
                        config=class_config,
                        selected_optional_subjects=[],
                        school=school,
                    )
                    if subject_error:
                        add_error(idx, row, subject_error)
                        continue

                subjects = _dedupe_keep_order(subjects or [])
                student_data = {
                    'firstname': full_name,
                    'email': email,
                    'date_of_birth': row.get('date_of_birth', ''),
                    'gender': row.get('gender', ''),
                    'classname': classname,
                    'first_year_class': first_year_class,
                    'term': term,
                    'stream': final_stream,
                    'number_of_subject': len(subjects),
                    'subjects': subjects,
                    'scores': {},
                    'promoted': normalize_promoted_db_value(promoted_raw in {'1', 'true', 'yes'}),
                    'parent_phone': row.get('parent_phone', ''),
                    'parent_password_hash': '',
                }
                try:
                    if not dry_run:
                        save_student(school_id, sid, student_data)
                        if not get_user(sid):
                            upsert_user(sid, hash_password(DEFAULT_STUDENT_PASSWORD), 'student', school_id)
                    imported += 1
                except Exception as exc:
                    add_error(idx, row, str(exc))
        elif target_key == 'teachers':
            for idx, row in enumerate(rows, start=2):
                tid = (row.get('user_id', '') or '').strip().lower()
                if not tid:
                    add_error(idx, row, 'user_id is required.')
                    continue
                processed += 1
                existing_user = get_user(tid)
                if existing_user:
                    existing_role = (existing_user.get('role') or '').strip().lower()
                    existing_school = (existing_user.get('school_id') or '').strip()
                    if not (existing_role == 'teacher' and existing_school == school_id):
                        add_error(idx, row, f'user_id "{tid}" already belongs to another account/school.')
                        continue
                if not is_valid_email(tid):
                    add_error(idx, row, 'user_id must be a valid email address.')
                    continue
                firstname = normalize_person_name(row.get('firstname', ''))
                lastname = normalize_person_name(row.get('lastname', ''))
                if not firstname or not lastname:
                    add_error(idx, row, 'firstname and lastname are required.')
                    continue
                gender = normalize_teacher_gender(row.get('gender', ''))
                if not gender:
                    add_error(idx, row, 'gender must be male/female/other.')
                    continue
                if not dry_run:
                    save_teacher(
                        school_id,
                        tid,
                        firstname,
                        lastname,
                        _safe_json_rows(row.get('assigned_classes')),
                        subjects_taught=normalize_subjects_list(row.get('subjects_taught', '')),
                        phone=row.get('phone', ''),
                        gender=gender,
                    )
                    if not get_user(tid):
                        upsert_user(tid, hash_password(DEFAULT_TEACHER_PASSWORD), 'teacher', school_id)
                imported += 1
        elif target_key == 'class_assignments':
            teachers_map = get_teachers(school_id)
            teacher_ids = {k.lower() for k in (teachers_map or {}).keys()}
            class_candidates = [str(c).strip() for c in (get_secondary_school_classnames(school_id) or []) if str(c).strip()]
            school = get_school(school_id) or {}
            default_year = (school.get('academic_year', '') or '').strip()
            for idx, row in enumerate(rows, start=2):
                teacher_id = (row.get('teacher_id', '') or '').strip().lower()
                classname = canonicalize_classname(row.get('classname', ''))
                term = (row.get('term', '') or '').strip()
                year = (row.get('academic_year', '') or '').strip() or default_year
                if not teacher_id or not classname or not term:
                    add_error(idx, row, 'teacher_id, classname, and term are required.')
                    continue
                processed += 1
                if teacher_id not in teacher_ids:
                    add_error(idx, row, f'teacher_id "{teacher_id}" not found in this school.')
                    continue
                teacher_profile = (teachers_map or {}).get(teacher_id, {}) or {}
                if int(teacher_profile.get('is_archived', 0) or 0):
                    add_error(idx, row, f'teacher_id "{teacher_id}" is archived.')
                    continue
                if class_candidates and not class_belongs_to_school_or_arm(school_id, classname, class_candidates=class_candidates):
                    add_error(idx, row, f'classname "{classname}" is not a valid class for this school.')
                    continue
                if not is_secondary_classname(classname):
                    add_error(idx, row, 'classname must be a secondary class (JSS/SS).')
                    continue
                arm_variants = class_arm_variants_for_base(class_candidates, classname)
                if arm_variants and not is_class_arm_variant(classname):
                    add_error(
                        idx,
                        row,
                        f'classname "{classname}" has arms configured. Use one of: ' + ', '.join(arm_variants),
                    )
                    continue
                if term not in {'First Term', 'Second Term', 'Third Term'}:
                    add_error(idx, row, 'term must be First Term, Second Term, or Third Term.')
                    continue
                if year and not re.fullmatch(r'^\d{4}-\d{4}$', year):
                    add_error(idx, row, 'academic_year must be in YYYY-YYYY format.')
                    continue
                try:
                    if not dry_run:
                        assign_teacher_to_class(school_id, teacher_id, classname, term, year)
                    imported += 1
                except Exception as exc:
                    add_error(idx, row, str(exc))
        else:
            raise ValueError('Invalid import target.')
        error_token = ''
        if error_rows:
            output = StringIO()
            fieldnames = list(reader.fieldnames or []) + ['Error', 'RowNumber']
            writer = csv.DictWriter(output, fieldnames=fieldnames)
            writer.writeheader()
            for item in error_rows:
                writer.writerow(item)
            error_token = _store_csv_error_export(
                output.getvalue(),
                f'{target_key}_import_errors.csv',
                owner_role='school_admin',
                owner_id=(session.get('user_id') or ''),
                school_id=(school_id or ''),
            )
            session['last_import_error_token'] = error_token
            session['last_import_target'] = target_key
            session['last_import_failed_rows'] = len(error_rows)
            session['last_import_at'] = datetime.now().isoformat()
            flash(
                f'{target_key.replace("_", " ").title()} {"dry-run" if dry_run else "import"} finished: {imported} valid row(s), {len(error_rows)} failed rows.',
                'error',
            )
        else:
            session.pop('last_import_error_token', None)
            session.pop('last_import_target', None)
            session.pop('last_import_failed_rows', None)
            session.pop('last_import_at', None)
            msg = f'{target_key.replace("_", " ").title()} {"dry-run" if dry_run else "import"} completed. {"Validated" if dry_run else "Imported"} {imported} row(s).'
            flash(msg, 'success')
        record_admin_action_audit(
            school_id,
            'bulk_import',
            target_scope=target_key,
            payload={'dry_run': dry_run, 'processed': processed, 'valid_rows': imported, 'failed_rows': len(error_rows)},
        )
        return redirect(url_for('school_admin_bulk_tools', error_token=error_token))
    except Exception as exc:
        flash(f'Import failed: {exc}', 'error')
    return redirect(url_for('school_admin_bulk_tools'))

