@app.route('/school-admin/add-students-by-class', methods=['GET', 'POST'])
def school_admin_add_students_by_class():
    """School admin can add multiple students to a class at once."""
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    
    school_id = session.get('school_id')
    school = get_school(school_id) or {}
    added_students = []
    selected_class = canonicalize_classname((request.args.get('class', '') or '').strip())
    current_term = get_current_term(school)
    valid_terms = {'First Term', 'Second Term', 'Third Term'}
    selected_term = (request.args.get('term', '') or '').strip() or current_term
    if selected_term not in valid_terms:
        selected_term = current_term
    
    if request.method == 'POST':
        classname = canonicalize_classname(request.form.get('classname', '').strip())
        first_year_class = classname  # First year class is the starting class
        term = (request.form.get('term', '') or '').strip() or current_term
        student_names = [normalize_person_name(name.strip()) for name in request.form.getlist('student_name[]')]
        reg_numbers = [reg.strip() for reg in request.form.getlist('reg_no[]')]
        student_emails = [(val or '').strip().lower() for val in request.form.getlist('student_email[]')]
        birth_dates = [(dob or '').strip() for dob in request.form.getlist('date_of_birth[]')]
        genders = [normalize_student_gender(gender) for gender in request.form.getlist('gender[]')]
        config = get_class_subject_config(school_id, classname)
        stream = 'N/A'

        if not classname or not term:
            flash('Please fill in all required fields.', 'error')
            return redirect(url_for('school_admin_add_students_by_class'))
        if term not in valid_terms:
            flash('Invalid term selected.', 'error')
            return redirect(url_for('school_admin_add_students_by_class'))
        if not is_secondary_classname(classname):
            flash('Only secondary classes are supported (JSS/SS).', 'error')
            return redirect(url_for('school_admin_add_students_by_class'))
        if not config:
            defaults = _catalog_defaults_for_class(classname)
            save_class_subject_config(
                school_id=school_id,
                classname=classname,
                core_subjects=defaults.get('core', []),
                science_subjects=defaults.get('science', []),
                art_subjects=defaults.get('art', []),
                commercial_subjects=defaults.get('commercial', []),
                optional_subjects=defaults.get('optional', []),
            )
            config = get_class_subject_config(school_id, classname)
            flash(f'Class subjects were auto-created for {classname}. You can edit them later in Class Subjects.', 'info')
        if not config:
            flash('No class subject configuration found. Configure subjects for this class first.', 'error')
            return redirect(url_for('school_admin_add_students_by_class'))
        if class_uses_stream_for_school(school, classname):
            # School admin can create SS students first; stream/track is allocated later by teacher.
            subjects = _dedupe_keep_order(config.get('core_subjects', []) or [])
            stream = 'N/A'
        else:
            subjects, stream, subject_error = build_subjects_from_config(
                classname=classname,
                stream='N/A',
                config=config,
                selected_optional_subjects=[],
                school=school,
            )
            if subject_error:
                flash(subject_error, 'error')
                return redirect(url_for('school_admin_add_students_by_class'))
            subjects = _dedupe_keep_order(subjects or [])
        number_of_subject = len(subjects)
        if number_of_subject <= 0:
            flash('This class has no core subjects configured. Update Class Subjects first.', 'error')
            return redirect(url_for('school_admin_add_students_by_class'))
        
        # Keep only rows with name; reg no is optional.
        rows = []
        for idx, name in enumerate(student_names):
            if not name:
                continue
            reg_no = reg_numbers[idx] if idx < len(reg_numbers) else ''
            email = student_emails[idx] if idx < len(student_emails) else ''
            date_of_birth = birth_dates[idx] if idx < len(birth_dates) else ''
            gender = genders[idx] if idx < len(genders) else ''
            if not date_of_birth:
                flash(f'Date of birth is required for {name}.', 'error')
                continue
            if not gender:
                flash(f'Gender is required for {name}.', 'error')
                continue
            if email and not is_valid_email(email):
                flash(f'Invalid email for {name}.', 'error')
                continue
            rows.append({
                'firstname': name,
                'reg_no': reg_no,
                'email': email,
                'date_of_birth': date_of_birth,
                'gender': gender,
            })
        if not rows:
            flash('Add at least one student name.', 'error')
            return redirect(url_for('school_admin_add_students_by_class'))
        try:
            ensure_school_plan_capacity(school_id, add_students=len(rows), add_teachers=0)
        except Exception as exc:
            flash(str(exc), 'error')
            return redirect(url_for('school_admin_add_students_by_class'))

        # First-time class setup: generate IDs based on alphabetical class list order.
        if not load_students(school_id, class_filter=classname):
            rows.sort(key=lambda r: (r.get('firstname', '').strip().lower(), r.get('reg_no', '').strip().lower()))
        
        # Starting index for generated IDs: append after the last student index in this class.
        next_index = get_next_student_index_for_class(school_id, classname)
        batch_ids = set()
        
        # Add each student. Use provided Reg No if present; otherwise auto-generate.
        for row in rows:
            firstname = normalize_person_name(row['firstname'])
            reg_no = row['reg_no']
            
            if reg_no:
                student_id = with_school_suffix_manual_id(reg_no, school_id)
                if not is_valid_manual_student_id(student_id):
                    flash(
                        f'Invalid Reg No. "{reg_no}" for {firstname}. Use only letters, numbers, /, -, _.',
                        'error'
                    )
                    continue
            else:
                current_index = next_index
                student_id = generate_student_id(school_id, current_index, first_year_class)
                # Ensure uniqueness even if a collision exists.
                while load_student(school_id, student_id, include_archived=True):
                    current_index += 1
                    student_id = generate_student_id(school_id, current_index, first_year_class)
                next_index = current_index + 1

            if student_id.lower() in batch_ids:
                flash(f'Duplicate ID "{student_id}" in the submitted table. Skipped {firstname}.', 'error')
                continue
            batch_ids.add(student_id.lower())

            # Avoid ID collision in school, including archived records.
            existing_student_any = load_student(school_id, student_id, include_archived=True)
            if existing_student_any:
                if int(existing_student_any.get('is_archived', 0) or 0):
                    flash(
                        f'ID "{student_id}" exists in archived records. Restore that student instead of re-adding.',
                        'error',
                    )
                else:
                    flash(f'ID "{student_id}" already exists. Skipped {firstname}.', 'error')
                continue
            
            student_data = {
                'firstname': firstname,
                'email': row.get('email', ''),
                'date_of_birth': row.get('date_of_birth', ''),
                'gender': row.get('gender', ''),
                'classname': classname,
                'first_year_class': first_year_class,
                'term': term,
                'stream': stream,
                'number_of_subject': number_of_subject,
                'subjects': subjects,
                'scores': {},
                'promoted': 0
            }
            
            try:
                # Keep student row + login row atomic to avoid partial writes.
                with db_connection(commit=True) as conn:
                    c = conn.cursor()
                    existing_user = get_user(student_id)
                    if existing_user:
                        existing_role = (existing_user.get('role') or '').strip().lower()
                        existing_school = (existing_user.get('school_id') or '').strip()
                        if not (existing_role == 'student' and existing_school == school_id):
                            raise ValueError(
                                f'ID "{student_id}" is already used by another account '
                                f'({existing_role or "unknown"}).'
                            )
                    save_student_with_cursor(c, school_id, student_id, student_data)
                    if not existing_user:
                        upsert_user_with_cursor(c, student_id, hash_password(DEFAULT_STUDENT_PASSWORD), 'student', school_id)
                
                added_students.append({
                    'student_id': student_id,
                    'firstname': firstname,
                    'date_of_birth': row.get('date_of_birth', ''),
                    'gender': row.get('gender', ''),
                })
            except Exception as e:
                flash(f'Error adding student {firstname}: {str(e)}', 'error')
        
        if added_students:
            flash(f'Successfully added {len(added_students)} students to {classname}!', 'success')
            # Redirect to GET to prevent accidental form resubmission on refresh
            return redirect(
                f'{url_for("school_admin_add_students_by_class")}?class={urllib.parse.quote(classname)}&term={urllib.parse.quote(term)}'
            )

    # Always build listing from fresh DB state so ordering and new additions are correct.
    all_students = load_students(school_id, include_archived=True)
    class_options = filter_secondary_classnames(
        {s.get('classname') for s in all_students.values() if s.get('classname')}
    )
    class_students = [
        {
            'student_id': sid,
            'firstname': data.get('firstname', ''),
            'email': data.get('email', ''),
            'date_of_birth': data.get('date_of_birth', ''),
            'gender': data.get('gender', ''),
            'term': data.get('term', ''),
            'stream': data.get('stream', ''),
            'is_archived': int(data.get('is_archived', 0) or 0),
        }
        for sid, data in all_students.items()
        if selected_class and data.get('classname') == selected_class
    ]
    class_students.sort(key=lambda s: ((s.get('firstname') or '').strip().lower(), (s.get('student_id') or '').strip().lower()))

    return render_template(
        'school/add_students_by_class.html',
        added_students=added_students,
        class_options=class_options,
        selected_class=selected_class,
        class_students=class_students,
        current_term=current_term,
        selected_term=selected_term,
    )

@app.route('/school-admin/assign-teacher', methods=['POST'])
def school_admin_assign_teacher():
    """Assign a teacher to a class."""
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    
    school_id = session.get('school_id')
    fallback_redirect = safe_referrer_or(url_for('school_admin_dashboard'))
    teacher_id = request.form.get('teacher_id', '').strip()
    classname = canonicalize_classname(request.form.get('classname', '').strip())
    school = get_school(school_id) or {}
    term = (request.form.get('term', '') or '').strip() or get_current_term(school)
    valid_terms = {'First Term', 'Second Term', 'Third Term'}
    if term not in valid_terms:
        flash('Invalid term selected.', 'error')
        return redirect(fallback_redirect)
    if classname and not is_secondary_classname(classname):
        flash('Only secondary classes are supported (JSS/SS).', 'error')
        return redirect(fallback_redirect)
    
    if teacher_id and classname:
        try:
            if teacher_id not in get_teachers(school_id):
                flash('Selected teacher does not belong to your school.', 'error')
                return redirect(fallback_redirect)
            teacher_profile = get_teachers(school_id).get(teacher_id, {}) or {}
            if int(teacher_profile.get('is_archived', 0) or 0):
                flash('Selected teacher is archived. Restore teacher before assigning.', 'error')
                return redirect(fallback_redirect)
            class_candidates = get_secondary_school_classnames(school_id)
            if not class_belongs_to_school_or_arm(school_id, classname, class_candidates=class_candidates):
                flash('Selected class does not exist for your school.', 'error')
                return redirect(fallback_redirect)
            arm_variants = class_arm_variants_for_base(class_candidates, classname)
            if arm_variants and not is_class_arm_variant(classname):
                flash(
                    f'{classname} has class arms configured. Assign a specific arm: '
                    + ', '.join(arm_variants[:6])
                    + ('...' if len(arm_variants) > 6 else ''),
                    'error',
                )
                return redirect(fallback_redirect)
            school = get_school(school_id)
            academic_year = (school.get('academic_year', '') or '').strip() if school else ''
            assign_teacher_to_class(school_id, teacher_id, classname, term, academic_year)
            record_admin_action_audit(
                school_id,
                'assign_teacher_class',
                target_scope=f'{classname}:{teacher_id}',
                payload={'term': term, 'academic_year': academic_year},
            )
            flash(f'Teacher assigned to {classname} successfully!', 'success')
        except Exception as e:
            flash(f'Error assigning teacher: {str(e)}', 'error')
    else:
        flash('Please select a teacher and class.', 'error')
    
    return redirect(fallback_redirect)

@app.route('/school-admin/assign-subject-teacher', methods=['POST'])
def school_admin_assign_subject_teacher():
    """Assign a teacher to one or more subjects in one/many compatible classes."""
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))

    school_id = session.get('school_id')
    fallback_redirect = safe_referrer_or(url_for('school_admin_dashboard'))
    teacher_id = request.form.get('teacher_id', '').strip()
    school = get_school(school_id) or {}
    term = (request.form.get('term', '') or '').strip() or get_current_term(school)
    assignment_scope = (request.form.get('assignment_scope', 'all_compatible') or 'all_compatible').strip().lower()
    legacy_classname = canonicalize_classname(request.form.get('classname', '').strip())
    selected_classnames = [
        canonicalize_classname(str(c).strip())
        for c in request.form.getlist('target_classnames')
        if str(c).strip()
    ]
    subject_values = request.form.getlist('subjects')
    if not subject_values:
        subject_values = request.form.getlist('subjects[]')
    if subject_values:
        subjects = normalize_subjects_list(subject_values)
    else:
        subjects = normalize_subjects_list(request.form.get('subjects', ''))
    valid_terms = {'First Term', 'Second Term', 'Third Term'}
    if term not in valid_terms:
        flash('Invalid term selected.', 'error')
        return redirect(fallback_redirect)

    if not teacher_id:
        flash('Please select teacher.', 'error')
        return redirect(fallback_redirect)
    if teacher_id not in get_teachers(school_id):
        flash('Selected teacher does not belong to your school.', 'error')
        return redirect(fallback_redirect)
    teacher_profile = get_teachers(school_id).get(teacher_id, {}) or {}
    if int(teacher_profile.get('is_archived', 0) or 0):
        flash('Selected teacher is archived. Restore teacher before assigning.', 'error')
        return redirect(fallback_redirect)
    if not subjects:
        flash('Select at least one subject for assignment.', 'error')
        return redirect(fallback_redirect)
    invalid_classnames = [cls for cls in selected_classnames if cls and not is_secondary_classname(cls)]
    if invalid_classnames:
        flash('Only secondary classes are supported (JSS/SS).', 'error')
        return redirect(fallback_redirect)

    try:
        school = get_school(school_id)
        academic_year = (school.get('academic_year', '') or '').strip() if school else ''

        class_candidates = get_secondary_school_classnames(school_id)
        if not class_candidates:
            flash('No classes available for subject assignment yet.', 'error')
            return redirect(fallback_redirect)
        class_candidates = _dedupe_keep_order([
            canonicalize_classname(str(c).strip())
            for c in class_candidates
            if str(c).strip()
        ])

        extra_classnames = []
        if assignment_scope == 'selected':
            if not selected_classnames and legacy_classname:
                selected_classnames = [legacy_classname]
            for cls in selected_classnames:
                if cls in class_candidates:
                    continue
                if class_belongs_to_school_or_arm(school_id, cls, class_candidates=class_candidates):
                    extra_classnames.append(cls)
                else:
                    flash(
                        'Selected class(es) are not valid for this school: ' + ', '.join([cls]),
                        'error',
                    )
                    return redirect(fallback_redirect)
        if extra_classnames:
            class_candidates = class_candidates + [cls for cls in extra_classnames if cls not in class_candidates]

        arm_variants_by_base = {}
        for cls in class_candidates:
            if not is_class_arm_variant(cls):
                continue
            base_key = class_arm_ranking_group(cls, mode='together')
            arm_variants_by_base.setdefault(base_key, [])
            if cls not in arm_variants_by_base[base_key]:
                arm_variants_by_base[base_key].append(cls)

        class_subject_options = {}
        for cls in class_candidates:
            config = get_class_subject_config(school_id, cls) or {}
            if not config and is_class_arm_variant(cls):
                base_group = class_arm_ranking_group(cls, mode='together')
                base_match = next(
                    (
                        c for c in class_candidates
                        if class_arm_ranking_group(c, mode='together') == base_group
                        and not is_class_arm_variant(c)
                    ),
                    '',
                )
                if not base_match:
                    base_match = next(
                        (
                            c for c in class_candidates
                            if class_arm_ranking_group(c, mode='together') == base_group
                        ),
                        '',
                    )
                if base_match and base_match != cls:
                    config = get_class_subject_config(school_id, base_match) or config
            cls_subjects = normalize_subjects_list(
                (config.get('core_subjects') or [])
                + (config.get('science_subjects') or [])
                + (config.get('art_subjects') or [])
                + (config.get('commercial_subjects') or [])
                + (config.get('optional_subjects') or [])
            )
            if not cls_subjects:
                defaults = _catalog_defaults_for_class(cls)
                cls_subjects = normalize_subjects_list(
                    (defaults.get('core') or [])
                    + (defaults.get('science') or [])
                    + (defaults.get('art') or [])
                    + (defaults.get('commercial') or [])
                    + (defaults.get('optional') or [])
                )
            class_subject_options[cls] = set(cls_subjects)

        compatible_classes = [
            cls for cls in class_candidates
            if all(subj in (class_subject_options.get(cls) or set()) for subj in subjects)
        ]
        if arm_variants_by_base:
            compatible_classes = [
                cls for cls in compatible_classes
                if not (class_arm_ranking_group(cls, mode='together') in arm_variants_by_base and not is_class_arm_variant(cls))
            ]
        if not compatible_classes:
            flash(
                'No compatible class found for selected subject(s): ' + ', '.join(subjects),
                'error',
            )
            return redirect(fallback_redirect)

        if assignment_scope == 'selected':
            if not selected_classnames:
                flash('Select at least one class or use "All compatible classes".', 'error')
                return redirect(fallback_redirect)
            invalid_arm_base = [
                cls for cls in selected_classnames
                if (
                    class_arm_ranking_group(cls, mode='together') in arm_variants_by_base
                    and not is_class_arm_variant(cls)
                )
            ]
            if invalid_arm_base:
                flash(
                    'Classes with arms must be assigned per arm. Choose one of: '
                    + ', '.join(_dedupe_keep_order([arm for cls in invalid_arm_base for arm in arm_variants_by_base.get(class_arm_ranking_group(cls, mode="together"), [])])[:8]),
                    'error',
                )
                return redirect(fallback_redirect)
            invalid_classes = [cls for cls in selected_classnames if cls not in compatible_classes]
            if invalid_classes:
                flash(
                    'Selected class(es) are not compatible with chosen subject(s): ' + ', '.join(invalid_classes),
                    'error',
                )
                return redirect(fallback_redirect)
            target_classes = [cls for cls in class_candidates if cls in set(selected_classnames)]
        else:
            target_classes = compatible_classes

        # Enforce one-teacher-per-subject-per-class for the same term/year.
        existing_assignments = get_teacher_subject_assignments(
            school_id,
            term=term,
            academic_year=academic_year,
        )
        teachers_map = get_teachers(school_id)
        existing_owner_by_key = {}
        for row in existing_assignments:
            cls_key = (row.get('classname') or '').strip().lower()
            subj_key = normalize_subject_name(row.get('subject', '')).lower()
            owner_teacher_id = (row.get('teacher_id') or '').strip()
            if not cls_key or not subj_key or not owner_teacher_id:
                continue
            existing_owner_by_key[(cls_key, subj_key)] = owner_teacher_id

        conflicts = []
        for cls in target_classes:
            cls_key = (cls or '').strip().lower()
            for subject in subjects:
                subj_key = normalize_subject_name(subject).lower()
                owner_teacher_id = existing_owner_by_key.get((cls_key, subj_key), '')
                if owner_teacher_id and owner_teacher_id != teacher_id:
                    owner_profile = teachers_map.get(owner_teacher_id, {}) or {}
                    owner_name = f"{owner_profile.get('firstname', '')} {owner_profile.get('lastname', '')}".strip()
                    owner_label = owner_name or owner_teacher_id
                    conflicts.append(f'{subject} ({cls}) already assigned to {owner_label}')
        if conflicts:
            flash(
                'Cannot assign duplicate class-subject owner. '
                + '; '.join(conflicts[:6])
                + ('...' if len(conflicts) > 6 else ''),
                'error',
            )
            return redirect(fallback_redirect)

        for cls in target_classes:
            assign_teacher_to_subjects(school_id, teacher_id, cls, subjects, term, academic_year)
        record_admin_action_audit(
            school_id,
            'assign_teacher_subject',
            target_scope=(teacher_id or ''),
            payload={'classes': target_classes, 'subjects': subjects, 'term': term, 'academic_year': academic_year},
        )

        flash(
            f'Subject assignment saved for {len(target_classes)} class(es): ' + ', '.join(target_classes[:8])
            + ('...' if len(target_classes) > 8 else ''),
            'success',
        )
    except Exception as e:
        flash(f'Error assigning subject teacher: {str(e)}', 'error')

    return redirect(fallback_redirect)

@app.route('/school-admin/send-student-message', methods=['POST'])
def school_admin_send_student_message():
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))

    school_id = session.get('school_id')
    admin_user_id = session.get('user_id')
    title = (request.form.get('title', '') or '').strip()
    message = (request.form.get('message', '') or '').strip()
    send_sms = (request.form.get('send_sms', '') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
    send_email = (request.form.get('send_email', '') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
    target_mode = (request.form.get('target_mode', 'all') or 'all').strip().lower()
    target_classname = canonicalize_classname((request.form.get('target_classname', '') or '').strip())
    target_stream = (request.form.get('target_stream', '') or '').strip()
    deadline_date = (request.form.get('deadline_date', '') or '').strip()

    if not title or not message:
        flash('Title and message are required.', 'error')
        return redirect(url_for('school_admin_messages'))

    if target_mode not in {'all', 'class', 'stream'}:
        target_mode = 'all'
    if target_mode == 'all':
        target_classname = ''
        target_stream = ''
    elif target_mode == 'class':
        if not target_classname:
            flash('Select class target for this message.', 'error')
            return redirect(url_for('school_admin_messages'))
        target_stream = ''
    else:  # stream
        if not target_classname:
            flash('Select class for stream-targeted message.', 'error')
            return redirect(url_for('school_admin_messages'))
    school = get_school(school_id) or {}
    class_candidates = get_secondary_school_classnames(school_id) or []
    class_candidates_canon = {canonicalize_classname(c) for c in class_candidates if str(c).strip()}
    if target_mode in {'class', 'stream'}:
        if target_classname and target_classname not in class_candidates_canon:
            flash('Selected class is not valid for your school.', 'error')
            return redirect(url_for('school_admin_messages'))
        if target_classname and not is_secondary_classname(target_classname):
            flash('Only secondary classes are supported (JSS/SS).', 'error')
            return redirect(url_for('school_admin_messages'))
    if target_mode == 'stream':
        normalized_stream, stream_error = normalize_stream_for_class(target_classname, target_stream, school)
        if stream_error:
            flash(stream_error, 'error')
            return redirect(url_for('school_admin_messages'))
        target_stream = normalized_stream or ''

    try:
        attachment = {}
        attachment_file = request.files.get('attachment_file')
        if attachment_file and (attachment_file.filename or '').strip():
            attachment = save_student_message_attachment(
                file_obj=attachment_file,
                school_id=school_id,
                created_by=admin_user_id,
            )
        create_student_message(
            school_id=school_id,
            title=title,
            message=message,
            target_classname=target_classname,
            target_stream=target_stream,
            target_subject='',
            message_context='messages',
            deadline_date=deadline_date,
            created_by=admin_user_id,
            attachment_path=attachment.get('attachment_path', ''),
            attachment_thumb_path=attachment.get('attachment_thumb_path', ''),
            attachment_name=attachment.get('attachment_name', ''),
            attachment_mime=attachment.get('attachment_mime', ''),
            attachment_size=attachment.get('attachment_size', 0),
            attachment_scan_status=attachment.get('attachment_scan_status', 'clean'),
        )
        recipient_estimate = 0
        sms_result = {'sent_sms': 0, 'errors': []}
        email_result = {'sent_email': 0, 'errors': []}
        sms_recipients = set()
        email_recipients = set()
        try:
            students_pool = load_students(school_id)
            for _sid, st in (students_pool or {}).items():
                student_id = (st.get('student_id') or _sid or '').strip()
                if target_classname and (st.get('classname') or '').strip() != target_classname:
                    continue
                if target_stream and (st.get('stream') or '').strip() != target_stream:
                    continue
                recipient_estimate += 1
                if send_sms:
                    for phone in (st.get('parent_phone', ''), st.get('parent_phone_2', '')):
                        normalized = normalize_parent_phone(phone)
                        if normalized and is_valid_parent_phone(normalized):
                            prefs = load_parent_notification_prefs(school_id, normalized, student_id) if student_id else {}
                            if not parent_pref_allows(prefs, 'messages'):
                                continue
                            sms_recipients.add(normalized)
                if send_email:
                    email = (st.get('email') or '').strip().lower()
                    if email and is_valid_email(email):
                        email_recipients.add(email)
        except Exception:
            recipient_estimate = 0
        if send_sms:
            school = get_school(school_id) or {}
            sms_body = f"{title}\n{message}".strip()
            sms_result = send_bulk_sms_messages(
                sorted(sms_recipients),
                sms_body,
                school_name=school.get('school_name', ''),
                context='student_message',
                school_id=school_id,
                audience_role='parent',
            )
        if send_email:
            email_body = f"{message}".strip()
            email_result = send_bulk_email_messages(
                sorted(email_recipients),
                title,
                email_body,
                context='student_message',
            )
        job_id = enqueue_notification_job(
            school_id=school_id,
            audience_role='student',
            title=title,
            body=message,
            target_scope=(f'class={target_classname};stream={target_stream}' if (target_classname or target_stream) else 'all'),
            recipients_estimate=recipient_estimate,
            channel='in_app',
            created_by=admin_user_id,
        )
        process_notification_queue_inline(school_id, max_jobs=10)
        record_admin_action_audit(
            school_id,
            'send_student_message',
            target_scope=(target_classname or 'all'),
            payload={
                'target_mode': target_mode,
                'target_stream': target_stream,
                'deadline_date': deadline_date,
                'queue_job_id': job_id,
                'sms_sent': sms_result.get('sent_sms', 0),
                'sms_errors': sms_result.get('errors', [])[:3],
                'email_sent': email_result.get('sent_email', 0),
                'email_errors': email_result.get('errors', [])[:3],
            },
        )
        flash('Student message sent successfully.', 'success')
        if send_sms:
            if sms_result.get('sent_sms'):
                flash(f"SMS sent to {sms_result.get('sent_sms', 0)} parent(s).", 'success')
            if sms_result.get('errors'):
                flash(f"SMS issues: {sms_result.get('errors')[0]}", 'warning')
        if send_email:
            if email_result.get('sent_email'):
                flash(f"Email sent to {email_result.get('sent_email', 0)} student(s).", 'success')
            if email_result.get('errors'):
                flash(f"Email issues: {email_result.get('errors')[0]}", 'warning')
    except Exception as exc:
        flash(f'Failed to send student message: {exc}', 'error')
    return redirect(url_for('school_admin_messages'))

@app.route('/school-admin/send-teacher-message', methods=['POST'])
def school_admin_send_teacher_message():
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    school_id = session.get('school_id')
    admin_user_id = session.get('user_id')
    title = (request.form.get('title', '') or '').strip()
    message = (request.form.get('message', '') or '').strip()
    send_sms = (request.form.get('send_sms', '') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
    send_email = (request.form.get('send_email', '') or '').strip().lower() in {'1', 'true', 'yes', 'on'}
    target_mode = (request.form.get('target_mode', 'all') or 'all').strip().lower()
    target_classname = canonicalize_classname((request.form.get('target_classname', '') or '').strip())
    target_subject = normalize_subject_name(request.form.get('target_subject', ''))
    deadline_date = (request.form.get('deadline_date', '') or '').strip()
    if target_mode not in {'all', 'class', 'subject', 'class_subject'}:
        target_mode = 'all'
    if not title or not message:
        flash('Title and message are required.', 'error')
        return redirect(url_for('school_admin_messages'))
    if target_mode == 'all':
        target_classname = ''
        target_subject = ''
    elif target_mode == 'class':
        if not target_classname:
            flash('Select class target for teacher message.', 'error')
            return redirect(url_for('school_admin_messages'))
        target_subject = ''
    elif target_mode == 'subject':
        if not target_subject:
            flash('Select subject target for teacher message.', 'error')
            return redirect(url_for('school_admin_messages'))
        target_classname = ''
    else:
        if not target_classname or not target_subject:
            flash('Select both class and subject for this teacher message target.', 'error')
            return redirect(url_for('school_admin_messages'))

    class_candidates = get_secondary_school_classnames(school_id) or []
    class_candidates_canon = {canonicalize_classname(c) for c in class_candidates if str(c).strip()}
    if target_mode in {'class', 'class_subject'}:
        if target_classname and target_classname not in class_candidates_canon:
            flash('Selected class is not valid for your school.', 'error')
            return redirect(url_for('school_admin_messages'))
        if target_classname and not is_secondary_classname(target_classname):
            flash('Only secondary classes are supported (JSS/SS).', 'error')
            return redirect(url_for('school_admin_messages'))

    def _subjects_for_class(cls_name):
        config = get_class_subject_config(school_id, cls_name) or {}
        cls_subjects = normalize_subjects_list(
            (config.get('core_subjects') or [])
            + (config.get('science_subjects') or [])
            + (config.get('art_subjects') or [])
            + (config.get('commercial_subjects') or [])
            + (config.get('optional_subjects') or [])
        )
        if not cls_subjects:
            defaults = _catalog_defaults_for_class(cls_name)
            cls_subjects = normalize_subjects_list(
                (defaults.get('core') or [])
                + (defaults.get('science') or [])
                + (defaults.get('art') or [])
                + (defaults.get('commercial') or [])
                + (defaults.get('optional') or [])
            )
        return set(normalize_subject_name(s) for s in cls_subjects if s)

    if target_mode == 'subject' and target_subject:
        subject_exists = any(
            target_subject in _subjects_for_class(cls_name)
            for cls_name in class_candidates
        )
        if not subject_exists:
            flash('Selected subject is not configured for your school.', 'error')
            return redirect(url_for('school_admin_messages'))
    if target_mode == 'class_subject' and target_subject and target_classname:
        if target_subject not in _subjects_for_class(target_classname):
            flash('Selected subject is not configured for that class.', 'error')
            return redirect(url_for('school_admin_messages'))
    try:
        attachment = {}
        attachment_file = request.files.get('attachment_file')
        if attachment_file and (attachment_file.filename or '').strip():
            attachment = save_student_message_attachment(
                file_obj=attachment_file,
                school_id=school_id,
                created_by=admin_user_id,
            )
        create_teacher_message(
            school_id=school_id,
            title=title,
            message=message,
            target_classname=target_classname,
            target_subject=target_subject,
            deadline_date=deadline_date,
            created_by=admin_user_id,
            attachment_path=attachment.get('attachment_path', ''),
            attachment_thumb_path=attachment.get('attachment_thumb_path', ''),
            attachment_name=attachment.get('attachment_name', ''),
            attachment_mime=attachment.get('attachment_mime', ''),
            attachment_size=attachment.get('attachment_size', 0),
            attachment_scan_status=attachment.get('attachment_scan_status', 'clean'),
        )
        recipient_estimate = 0
        sms_result = {'sent_sms': 0, 'errors': []}
        email_result = {'sent_email': 0, 'errors': []}
        sms_recipients = set()
        email_recipients = set()
        try:
            teacher_map = get_teachers(school_id) or {}
            school = get_school(school_id) or {}
            current_term = get_current_term(school)
            current_year = (school or {}).get('academic_year', '')

            def _resolve_teacher_ids():
                if target_mode == 'all':
                    return set(teacher_map.keys())
                if target_mode == 'class':
                    ids = set()
                    for row in get_class_assignments(school_id):
                        if target_classname and (row.get('classname') or '').strip() != target_classname:
                            continue
                        if current_term and (row.get('term') or '').strip().lower() != current_term.lower():
                            continue
                        if current_year and (row.get('academic_year') or '') != current_year:
                            continue
                        ids.add((row.get('teacher_id') or '').strip())
                    return ids
                if target_mode == 'subject':
                    ids = set()
                    for row in get_teacher_subject_assignments(
                        school_id,
                        term=current_term,
                        academic_year=current_year,
                    ):
                        if target_subject and normalize_subject_name(row.get('subject', '')) != target_subject:
                            continue
                        ids.add((row.get('teacher_id') or '').strip())
                    return ids
                ids = set()
                for row in get_teacher_subject_assignments(
                    school_id,
                    term=current_term,
                    academic_year=current_year,
                    classname=target_classname,
                ):
                    if target_subject and normalize_subject_name(row.get('subject', '')) != target_subject:
                        continue
                    ids.add((row.get('teacher_id') or '').strip())
                return ids

            teacher_ids = _resolve_teacher_ids()
            recipient_estimate = len(teacher_ids)
            if send_sms:
                for tid in teacher_ids:
                    profile = teacher_map.get(tid, {}) or {}
                    phone = (profile.get('phone') or '').strip()
                    normalized = normalize_sms_phone(phone, SMS_DEFAULT_COUNTRY_CODE)
                    if normalized:
                        sms_recipients.add(normalized)
            if send_email:
                for tid in teacher_ids:
                    if tid and is_valid_email(tid):
                        email_recipients.add(tid.strip().lower())
        except Exception:
            recipient_estimate = 0
        if send_sms:
            school = get_school(school_id) or {}
            sms_body = f"{title}\n{message}".strip()
            sms_result = send_bulk_sms_messages(
                sorted(sms_recipients),
                sms_body,
                school_name=school.get('school_name', ''),
                context='teacher_message',
                school_id=school_id,
                audience_role='teacher',
            )
        if send_email:
            email_body = f"{message}".strip()
            email_result = send_bulk_email_messages(
                sorted(email_recipients),
                title,
                email_body,
                context='teacher_message',
            )
        job_id = enqueue_notification_job(
            school_id=school_id,
            audience_role='teacher',
            title=title,
            body=message,
            target_scope=(f'class={target_classname};subject={target_subject}' if (target_classname or target_subject) else 'all'),
            recipients_estimate=recipient_estimate,
            channel='in_app',
            created_by=admin_user_id,
        )
        process_notification_queue_inline(school_id, max_jobs=10)
        record_admin_action_audit(
            school_id,
            'send_teacher_message',
            target_scope=(target_classname or target_subject or 'all'),
            payload={
                'target_mode': target_mode,
                'deadline_date': deadline_date,
                'queue_job_id': job_id,
                'sms_sent': sms_result.get('sent_sms', 0),
                'sms_errors': sms_result.get('errors', [])[:3],
                'email_sent': email_result.get('sent_email', 0),
                'email_errors': email_result.get('errors', [])[:3],
            },
        )
        flash('Teacher message sent successfully.', 'success')
        if send_sms:
            if sms_result.get('sent_sms'):
                flash(f"SMS sent to {sms_result.get('sent_sms', 0)} teacher(s).", 'success')
            if sms_result.get('errors'):
                flash(f"SMS issues: {sms_result.get('errors')[0]}", 'warning')
        if send_email:
            if email_result.get('sent_email'):
                flash(f"Email sent to {email_result.get('sent_email', 0)} teacher(s).", 'success')
            if email_result.get('errors'):
                flash(f"Email issues: {email_result.get('errors')[0]}", 'warning')
    except Exception as exc:
        flash(f'Failed to send teacher message: {exc}', 'error')
    return redirect(url_for('school_admin_messages'))

@app.route('/school-admin/toggle-operations', methods=['POST'])
def school_admin_toggle_operations():
    """School admin can toggle teacher editing operations only."""
    if session.get('role') != 'school_admin':
        return redirect(url_for('login'))
    school_id = session.get('school_id')
    if not get_school(school_id):
        flash('School not found. Toggle failed.', 'error')
        return redirect(url_for('school_admin_dashboard'))
    enabled = request.form.get('teacher_operations_enabled', '1').strip() == '1'
    affected = set_teacher_operations_enabled(school_id, enabled)
    # Some mocked/legacy implementations may return None; treat as non-failing best-effort.
    affected_count = 1 if affected is None else safe_int(affected, 0)
    if affected_count < 1:
        flash('School not found. Toggle failed.', 'error')
        return redirect(url_for('school_admin_dashboard'))
    record_admin_action_audit(
        school_id,
        'toggle_teacher_operations',
        target_scope='teacher_operations',
        payload={'teacher_operations_enabled': 1 if enabled else 0},
    )
    state = 'ON' if enabled else 'OFF'
    flash(f'Teacher operations set to {state}.', 'success')
    return redirect(url_for('school_admin_dashboard'))

@app.route('/school-admin/remove-teacher-assignment', methods=['POST'])
def school_admin_remove_teacher_assignment():
    """Remove a teacher assignment from a class."""
