@app.route('/teacher/subject-handover')
def teacher_subject_handover():
    if session.get('role') != 'teacher':
        return redirect(url_for('login'))
    school_id = session.get('school_id')
    teacher_id = session.get('user_id')
    school = get_school(school_id) or {}
    current_term = get_current_term(school)
    current_year = (school or {}).get('academic_year', '')
    assignments = get_teacher_subject_assignments(
        school_id,
        teacher_id=teacher_id,
        term=current_term,
        academic_year=current_year,
    )
    class_list = sorted({(row.get('classname') or '').strip() for row in assignments if (row.get('classname') or '').strip()})
    class_students_data = load_students_for_classes(school_id, class_list, term_filter=current_term) if class_list else {}
    report_rows = []
    for row in assignments:
        cls = (row.get('classname') or '').strip()
        subject = normalize_subject_name(row.get('subject', ''))
        if not cls or not subject:
            continue
        completion = compute_class_subject_completion(
            school_id,
            cls,
            current_term,
            academic_year=current_year,
            school=school,
            class_students_data=class_students_data,
        )
        progress_map = {normalize_subject_name(r.get('subject', '')): r for r in (completion.get('rows') or [])}
        progress = progress_map.get(subject, {})
        report_rows.append({
            'classname': cls,
            'subject': subject,
            'eligible_students': int(progress.get('eligible_students', 0) or 0),
            'completed_students': int(progress.get('completed_students', 0) or 0),
            'pending_students': int(progress.get('pending_students', 0) or 0),
            'ready': bool(progress.get('ready')),
        })
    report_rows.sort(key=lambda x: (x.get('classname', '').lower(), x.get('subject', '').lower()))
    return render_template(
        'teacher/teacher_subject_handover.html',
        school=school,
        current_term=current_term,
        current_year=current_year,
        report_rows=report_rows,
    )


@app.route('/teacher/notifications')
def teacher_notifications():
    if session.get('role') != 'teacher':
        return redirect(url_for('login'))

    school_id = session.get('school_id')
    teacher_id = session.get('user_id')
    school = get_school(school_id) or {}
    current_term = get_current_term(school)
    current_year = (school.get('academic_year', '') or '').strip()

    teacher_profile = get_teachers(school_id).get(teacher_id, {})
    teacher_name = f"{teacher_profile.get('firstname', '')} {teacher_profile.get('lastname', '')}".strip() or teacher_id
    teacher_phone = (teacher_profile.get('phone') or '').strip()
    teacher_profile_image = (teacher_profile.get('profile_image') or '').strip()
    last_login_at = format_timestamp(get_last_login_at(session.get('user_id')))

    classes = get_teacher_classes(school_id, teacher_id, term=current_term, academic_year=current_year)
    class_students_data = load_students_for_classes(school_id, classes, term_filter=current_term)
    class_students_data = {
        sid: row for sid, row in (class_students_data or {}).items()
        if (row.get('academic_year') or current_year) == current_year
    }
    subject_assignment_rows = get_teacher_subject_assignments(
        school_id,
        teacher_id=teacher_id,
        term=current_term,
        academic_year=current_year,
    )

    subject_map_by_class = {}
    subject_assignment_set = set()
    for row in subject_assignment_rows:
        cls = (row.get('classname') or '').strip()
        subj = normalize_subject_name(row.get('subject', ''))
        if not cls or not subj:
            continue
        subject_map_by_class.setdefault(cls, set()).add(subj)
        subject_assignment_set.add(subj)

    subject_students_data = load_students_for_classes(school_id, subject_map_by_class.keys(), term_filter=current_term)
    subject_students_data = {
        sid: row for sid, row in (subject_students_data or {}).items()
        if (row.get('academic_year') or current_year) == current_year
    }
    arm_mode = (school or {}).get('class_arm_ranking_mode', 'separate')
    arm_mode_override = (request.args.get('arm_mode') or '').strip().lower()
    if arm_mode_override in {'together', 'separate'}:
        arm_mode = arm_mode_override
    term_students_all = None
    if arm_mode == 'together':
        term_students_all = load_students(school_id, term_filter=current_term)
        term_students_all = {
            sid: row for sid, row in (term_students_all or {}).items()
            if (row.get('academic_year') or current_year) == current_year
        }

    def _class_match(student_classname, target_classname):
        if not student_classname or not target_classname:
            return False
        if arm_mode != 'together':
            return student_classname.strip().lower() == target_classname.strip().lower()
        return (
            class_arm_ranking_group(student_classname, mode='together')
            == class_arm_ranking_group(target_classname, mode='together')
        )

    class_publish_status = {}
    for classname in classes:
        source_students = term_students_all if term_students_all is not None else class_students_data
        class_students = [s for s in source_students.values() if _class_match(s.get('classname', ''), classname) and s.get('term') == current_term]
        class_student_ids = [sid for sid, s in source_students.items() if _class_match(s.get('classname', ''), classname) and s.get('term') == current_term]
        behaviour_progress = class_behaviour_completion(school_id, classname, current_term, current_year, class_student_ids)
        subject_progress = compute_class_subject_completion(
            school_id=school_id,
            classname=classname,
            term=current_term,
            academic_year=current_year,
            school=school,
            class_students_data={idx: s for idx, s in enumerate(class_students)},
        )
        subject_pending_count = sum(1 for row in subject_progress.get('rows', []) if int(row.get('pending_students', 0)) > 0)
        class_publish_status[classname] = {
            'subject_progress': subject_progress.get('rows', []),
            'subject_pending_count': subject_pending_count,
            'behaviour_missing_count': int(behaviour_progress.get('missing_count', 0) or 0),
        }

    teacher_missing_score_alerts = []
    for classname in classes:
        status_row = class_publish_status.get(classname, {})
        if int(status_row.get('subject_pending_count', 0) or 0) <= 0:
            continue
        pending_subject_names = [
            row.get('subject', '')
            for row in (status_row.get('subject_progress') or [])
            if int(row.get('pending_students', 0) or 0) > 0
        ]
        teacher_missing_score_alerts.append({
            'scope': 'class_owner',
            'classname': classname,
            'subject': '',
            'pending_students': sum(
                int(row.get('pending_students', 0) or 0)
                for row in (status_row.get('subject_progress') or [])
                if int(row.get('pending_students', 0) or 0) > 0
            ),
            'message': f'{classname}: pending subjects - {", ".join(pending_subject_names[:6])}' + ('...' if len(pending_subject_names) > 6 else ''),
        })

    for classname in classes:
        status_row = class_publish_status.get(classname, {})
        if int(status_row.get('behaviour_missing_count', 0) or 0) > 0:
            teacher_missing_score_alerts.append({
                'scope': 'class_owner',
                'classname': classname,
                'subject': 'Behaviour Assessment',
                'pending_students': int(status_row.get('behaviour_missing_count', 0) or 0),
                'message': f'{classname}: behaviour assessment pending for {int(status_row.get("behaviour_missing_count", 0) or 0)} student(s).',
            })

    seen_subject_alerts = set()
    for row in subject_assignment_rows:
        classname = (row.get('classname') or '').strip()
        subject = normalize_subject_name(row.get('subject', ''))
        key = (classname.lower(), subject.lower())
        if not classname or not subject or key in seen_subject_alerts:
            continue
        seen_subject_alerts.add(key)
        eligible = 0
        completed = 0
        for student in (term_students_all if term_students_all is not None else subject_students_data).values():
            if not _class_match(student.get('classname', ''), classname):
                continue
            offered = {x.lower(): x for x in normalize_subjects_list(student.get('subjects', []))}
            subject_key = offered.get(subject.lower(), '')
            if not subject_key:
                continue
            eligible += 1
            score_block = get_subject_score_block((student.get('scores') or {}), subject_key)
            if is_score_complete_for_subject(score_block, school) and is_score_entry_confirmed(score_block, school):
                completed += 1
        pending = max(0, eligible - completed)
        if pending <= 0:
            continue
        teacher_missing_score_alerts.append({
            'scope': 'subject_teacher',
            'classname': classname,
            'subject': subject,
            'pending_students': pending,
            'message': f'{classname} - {subject}: {pending} student(s) pending.',
        })

    teacher_missing_score_alerts.sort(
        key=lambda x: (
            (x.get('scope', '') or '').lower(),
            -(int(x.get('pending_students', 0) or 0)),
            (x.get('classname', '') or '').lower(),
            (x.get('subject', '') or '').lower(),
        )
    )

    subject_classes = sorted({r.get('classname', '') for r in subject_assignment_rows if r.get('classname', '')})
    dashboard_classes = sorted(set(classes) | set(subject_classes))
    teacher_messages = get_teacher_messages_for_teacher(
        school_id=school_id,
        teacher_id=teacher_id,
        classes=dashboard_classes,
        subjects=list(subject_assignment_set),
        limit=20,
    )
    unread_teacher_messages = sum(1 for row in teacher_messages if not row.get('is_read'))

    return render_template(
        'teacher/teacher_notifications.html',
        school=school,
        active_page='notifications',
        teacher_id=teacher_id,
        teacher_name=teacher_name,
        teacher_phone=teacher_phone,
        teacher_profile_image=teacher_profile_image,
        classes=classes,
        current_term=current_term,
        current_year=current_year,
        last_login_at=last_login_at,
        teacher_missing_score_alerts=teacher_missing_score_alerts,
        missing_score_alert_count=len(teacher_missing_score_alerts),
        total_pending_entries=sum(int(x.get('pending_students', 0) or 0) for x in teacher_missing_score_alerts),
        teacher_sidebar_profile_image=teacher_profile_image,
        teacher_sidebar_display_name=teacher_name,
        teacher_unread_notifications=unread_teacher_messages,
        teacher_score_nav_tree=[],
        teacher_selected_score_subject='',
        teacher_selected_score_class='',
        teacher_has_class_assignment_nav=bool(classes),
    )


@app.route('/teacher/subject-comments')
def teacher_subject_comments():
    if session.get('role') != 'teacher':
        return redirect(url_for('login'))

    school_id = session.get('school_id')
    teacher_id = session.get('user_id')
    school = get_school(school_id) or {}
    current_term = get_current_term(school)
    current_year = (school.get('academic_year', '') or '').strip()

    teacher_profile = get_teachers(school_id).get(teacher_id, {})
    teacher_name = f"{teacher_profile.get('firstname', '')} {teacher_profile.get('lastname', '')}".strip() or teacher_id
    teacher_phone = (teacher_profile.get('phone') or '').strip()
    teacher_profile_image = (teacher_profile.get('profile_image') or '').strip()
    last_login_at = format_timestamp(get_last_login_at(session.get('user_id')))

    class_teacher_classes = get_teacher_classes(school_id, teacher_id, term=current_term, academic_year=current_year)
    subject_assignment_rows = get_teacher_subject_assignments(
        school_id,
        teacher_id=teacher_id,
        term=current_term,
        academic_year=current_year,
    )
    subject_assignment_by_class = {}
    subject_assignment_set = set()
    for row in subject_assignment_rows:
        cls = (row.get('classname') or '').strip()
        subj = normalize_subject_name(row.get('subject', ''))
        if not cls or not subj:
            continue
        subject_assignment_by_class.setdefault(cls, set()).add(subj)
        subject_assignment_set.add(subj)

    eligible_classes = sorted(set(class_teacher_classes) | set(subject_assignment_by_class.keys()))
    selected_class = (request.args.get('classname', '') or '').strip()
    if selected_class and selected_class not in eligible_classes:
        selected_class = ''

    selected_term = (request.args.get('term', '') or '').strip() or current_term
    selected_year = (request.args.get('academic_year', '') or '').strip() or current_year
    selected_subject = (request.args.get('subject', '') or '').strip()

    term_options = ['First Term', 'Second Term', 'Third Term']
    year_options = sorted({y for y in [current_year, selected_year] if y})
    if not year_options and current_year:
        year_options = [current_year]

    class_filter = [selected_class] if selected_class else eligible_classes
    class_students_data = load_students_for_classes(school_id, class_filter, term_filter=selected_term) if class_filter else {}

    available_subjects = set(subject_assignment_set)
    comment_rows = []
    for student_id, student in (class_students_data or {}).items():
        student_year = (student.get('academic_year') or selected_year).strip()
        if selected_year and student_year != selected_year:
            continue
        classname = (student.get('classname') or '').strip()
        if selected_class and classname.lower() != selected_class.lower():
            continue
        allowed_subjects = set()
        if classname in class_teacher_classes:
            allowed_subjects.update(normalize_subjects_list(student.get('subjects', [])))
        if classname in subject_assignment_by_class:
            allowed_subjects.update(subject_assignment_by_class.get(classname, set()))
        if not allowed_subjects:
            continue
        available_subjects.update(allowed_subjects)
        snapshot = None
        if selected_term:
            snapshot = load_published_student_result(school_id, student_id, selected_term, selected_year, classname=classname)
        score_source = 'published' if snapshot else 'live'
        scores = snapshot.get('scores', {}) if snapshot else (student.get('scores') or {})

        student_name = " ".join(
            [student.get('firstname', ''), student.get('lastname', ''), student.get('othername', '')]
        ).strip()
        if not student_name:
            student_name = student_id

        for subject in sorted(allowed_subjects):
            if selected_subject and subject.lower() != selected_subject.lower():
                continue
            score_block = get_subject_score_block(scores, subject)
            if not isinstance(score_block, dict):
                continue
            comment = (score_block.get('subject_teacher_comment', '') or '').strip()
            if not comment:
                continue
            comment_rows.append({
                'student_id': student_id,
                'student_name': student_name,
                'classname': classname,
                'subject': subject,
                'comment': comment,
                'term': selected_term,
                'academic_year': selected_year,
                'source': score_source,
            })

    comment_rows.sort(
        key=lambda row: (
            (row.get('classname', '') or '').lower(),
            (row.get('subject', '') or '').lower(),
            (row.get('student_name', '') or '').lower(),
            (row.get('student_id', '') or '').lower(),
        )
    )

    dashboard_classes = sorted(set(class_teacher_classes) | set(subject_assignment_by_class.keys()))
    teacher_messages = get_teacher_messages_for_teacher(
        school_id=school_id,
        teacher_id=teacher_id,
        classes=dashboard_classes,
        subjects=list(subject_assignment_set),
        limit=20,
    )
    unread_teacher_messages = sum(1 for row in teacher_messages if not row.get('is_read'))

    return render_template(
        'teacher/teacher_subject_comments.html',
        school=school,
        active_page='subject_comments',
        teacher_id=teacher_id,
        teacher_name=teacher_name,
        teacher_phone=teacher_phone,
        teacher_profile_image=teacher_profile_image,
        last_login_at=last_login_at,
        classes=eligible_classes,
        selected_class=selected_class,
        selected_subject=selected_subject,
        selected_term=selected_term,
        selected_year=selected_year,
        term_options=term_options,
        year_options=year_options,
        available_subjects=sorted(available_subjects),
        comment_rows=comment_rows,
        teacher_sidebar_profile_image=teacher_profile_image,
        teacher_sidebar_display_name=teacher_name,
        teacher_unread_notifications=unread_teacher_messages,
        teacher_score_nav_tree=[],
        teacher_selected_score_subject='',
        teacher_selected_score_class='',
        teacher_has_class_assignment_nav=bool(class_teacher_classes),
    )


@app.route('/teacher/class-list')
def teacher_class_list():
    if session.get('role') != 'teacher':
        return redirect(url_for('login'))

    school_id = session.get('school_id')
    teacher_id = session.get('user_id')
    school = get_school(school_id) or {}
    current_term = get_current_term(school)
    current_year = (school.get('academic_year', '') or '').strip()

    teacher_profile = get_teachers(school_id).get(teacher_id, {})
    teacher_name = f"{teacher_profile.get('firstname', '')} {teacher_profile.get('lastname', '')}".strip() or teacher_id
    teacher_phone = (teacher_profile.get('phone') or '').strip()
    teacher_profile_image = (teacher_profile.get('profile_image') or '').strip()
    last_login_at = format_timestamp(get_last_login_at(session.get('user_id')))

    classes = get_teacher_classes(school_id, teacher_id, term=current_term, academic_year=current_year)
    class_students_data = load_students_for_classes(school_id, classes, term_filter=current_term)
    subject_assignment_rows = get_teacher_subject_assignments(
        school_id,
        teacher_id=teacher_id,
        term=current_term,
        academic_year=current_year,
    )

    subject_assignment_by_class = {}
    subject_assignment_set = set()
    for row in subject_assignment_rows:
        cls = (row.get('classname') or '').strip()
        subj = normalize_subject_name(row.get('subject', ''))
        if not cls or not subj:
            continue
        subject_assignment_by_class.setdefault(cls, set()).add(subj)
        subject_assignment_set.add(subj)

    subject_classes = sorted({r.get('classname', '') for r in subject_assignment_rows if r.get('classname', '')})
    dashboard_classes = sorted(set(classes) | set(subject_classes))
    if set(dashboard_classes) == set(classes):
        students = class_students_data
    else:
        students = load_students_for_classes(school_id, dashboard_classes, term_filter=current_term)

    subject_map_by_class = {}
    for row in subject_assignment_rows:
        cls = (row.get('classname') or '').strip()
        subj = normalize_subject_name(row.get('subject', ''))
        if not cls or not subj:
            continue
        subject_map_by_class.setdefault(cls, set()).add(subj)

    class_owner_set = {(c or '').strip().lower() for c in classes}
    recent_students = []
    for sid, s in sorted(
        students.items(),
        key=lambda item: (
            (item[1].get('classname', '') or '').strip().lower(),
            (item[1].get('firstname', '') or '').strip().lower(),
            (item[0] or '').strip().lower(),
        ),
    ):
        classname = (s.get('classname') or '').strip()
        is_class_owner = classname.lower() in class_owner_set if classname else False
        offered_subjects = normalize_subjects_list(s.get('subjects', []))
        matched_subjects = []
        if not is_class_owner:
            allowed_for_class = subject_map_by_class.get(classname, set())
            if not allowed_for_class:
                continue
            matched_subjects = [x for x in offered_subjects if x in allowed_for_class]
            if not matched_subjects:
                continue
        student_view = dict(s)
        student_view['is_class_owner'] = bool(is_class_owner)
        student_view['matched_subjects'] = matched_subjects
        if is_class_owner:
            scope_complete = is_student_score_complete(s, school, current_term)
        else:
            scores_map = s.get('scores', {}) if isinstance(s.get('scores', {}), dict) else {}
            scope_complete = bool(matched_subjects) and all(
                is_score_complete_for_subject(
                    get_subject_score_block(scores_map, subj),
                    school,
                )
                for subj in matched_subjects
            )
        student_view['scope_complete'] = bool(scope_complete)
        recent_students.append((sid, student_view))

    viewed_student_ids = get_viewed_student_ids_for_classes(school_id, classes, current_term, current_year)
    pending_stream_students = {
        sid for sid, s in class_students_data.items()
        if class_uses_stream_for_school(school, s.get('classname', '')) and (s.get('stream') in ('', 'N/A', None))
    }
    stream_managed_students = {
        sid for sid, s in class_students_data.items()
        if class_uses_stream_for_school(school, s.get('classname', ''))
    }

    teacher_messages = get_teacher_messages_for_teacher(
        school_id=school_id,
        teacher_id=teacher_id,
        classes=dashboard_classes,
        subjects=list(subject_assignment_set),
        limit=20,
    )
    unread_teacher_messages = sum(1 for row in teacher_messages if not row.get('is_read'))

    viewed_count = sum(1 for sid, _s in recent_students if sid in viewed_student_ids)
    pending_view_count = max(0, len(recent_students) - viewed_count)

    return render_template(
        'teacher/teacher_class_list.html',
        active_page='class_list',
        school=school,
        teacher_id=teacher_id,
        teacher_name=teacher_name,
        teacher_phone=teacher_phone,
        teacher_profile_image=teacher_profile_image,
        classes=classes,
        has_class_assignment=bool(classes),
        current_term=current_term,
        current_year=current_year,
        last_login_at=last_login_at,
        recent_students=recent_students,
        viewed_student_ids=viewed_student_ids,
        pending_stream_students=pending_stream_students,
        stream_managed_students=stream_managed_students,
        unread_teacher_messages=unread_teacher_messages,
        viewed_count=viewed_count,
        pending_view_count=pending_view_count,
        teacher_sidebar_profile_image=teacher_profile_image,
        teacher_sidebar_display_name=teacher_name,
        teacher_unread_notifications=unread_teacher_messages,
        teacher_score_nav_tree=[],
        teacher_selected_score_subject='',
        teacher_selected_score_class='',
        teacher_has_class_assignment_nav=bool(classes),
    )

@app.route('/teacher/send-student-message', methods=['POST'])
def teacher_send_student_message():
    if session.get('role') != 'teacher':
        return redirect(url_for('login'))

    school_id = session.get('school_id')
    teacher_id = session.get('user_id')
    school = get_school(school_id) or {}
    current_term = get_current_term(school)
    current_year = (school.get('academic_year', '') or '').strip()

    message_kind = (request.form.get('message_kind', 'assignment') or 'assignment').strip().lower()
    if message_kind not in {'assignment', 'note'}:
        message_kind = 'assignment'

    classname = canonicalize_classname(request.form.get('target_classname', ''))
    subject = normalize_subject_name(request.form.get('target_subject', ''))
    title = (request.form.get('title', '') or '').strip()
    message = (request.form.get('message', '') or '').strip()
    deadline_date = (request.form.get('deadline_date', '') or '').strip()
    attachment_file = request.files.get('attachment_file') or request.files.get('attachment_image')

    if not classname or not subject:
        flash('Class and subject are required for student message.', 'error')
        return redirect(url_for('teacher_dashboard', tab='overview'))
    if not message:
        flash('Enter assignment/note details before sending.', 'error')
        return redirect(url_for('teacher_dashboard', tab='overview'))

    allowed = teacher_can_score_subject(
        school_id,
        teacher_id,
        classname,
        subject,
        term=current_term,
        academic_year=current_year,
    )
    if not allowed:
        flash('You are not assigned to that class/subject.', 'error')
        return redirect(url_for('teacher_dashboard', tab='overview'))

    if deadline_date and not _parse_iso_date(deadline_date):
        flash('Deadline must be in YYYY-MM-DD format.', 'error')
        return redirect(url_for('teacher_dashboard', tab='overview'))

    if not title:
        prefix = 'Assignment' if message_kind == 'assignment' else 'Note'
        title = f'{prefix}: {subject} ({classname})'

    body = f'Subject: {subject}\nClass: {classname}\n\n{message}'
    try:
        attachment = {}
        if attachment_file and (attachment_file.filename or '').strip():
            attachment = save_student_message_attachment(
                file_obj=attachment_file,
                school_id=school_id,
                created_by=f'teacher:{teacher_id}',
            )
        create_student_message(
            school_id=school_id,
            title=title,
            message=body,
            target_classname=classname,
            target_stream='',
            target_subject=subject,
            message_context=message_kind,
            deadline_date=deadline_date,
            created_by=f'teacher:{teacher_id}',
            attachment_path=attachment.get('attachment_path', ''),
            attachment_thumb_path=attachment.get('attachment_thumb_path', ''),
            attachment_name=attachment.get('attachment_name', ''),
            attachment_mime=attachment.get('attachment_mime', ''),
            attachment_size=attachment.get('attachment_size', 0),
            attachment_scan_status=attachment.get('attachment_scan_status', 'clean'),
        )
        recipient_estimate = 0
        try:
            class_students = load_students(school_id, class_filter=classname, term_filter=current_term)
            for _sid, st in (class_students or {}).items():
                offered = {x.lower() for x in normalize_subjects_list(st.get('subjects', []))}
                if subject.lower() in offered:
                    recipient_estimate += 1
        except Exception:
            recipient_estimate = 0
        enqueue_notification_job(
            school_id=school_id,
            audience_role='student',
            title=title,
            body=body,
            target_scope=f'class={classname};subject={subject}',
            recipients_estimate=recipient_estimate,
            channel='in_app',
            created_by=f'teacher:{teacher_id}',
        )
        process_notification_queue_inline(school_id, max_jobs=10)
        flash(f'{message_kind.title()} sent to {classname} students successfully.', 'success')
    except Exception as exc:
        flash(f'Failed to send {message_kind}: {exc}', 'error')
    return redirect(url_for('teacher_dashboard', tab='overview'))

