@app.route('/student/cbt')
def student_cbt():
    if session.get('role') != 'student':
        return redirect(url_for('login'))
    if not ensure_cbt_schema():
        flash('CBT module is not available right now. Please retry.', 'error')
        return redirect(url_for('student_dashboard'))

    school_id = session.get('school_id')
    student_id = session.get('user_id')
    student = load_student(school_id, student_id)
    if not student:
        flash('Student data not found.', 'error')
        return redirect(url_for('login'))

    school = get_school(school_id) or {}
    current_term = get_current_term(school)
    current_year = str((school or {}).get('academic_year', '') or '').strip()
    selected_term = str(request.args.get('term') or current_term or '').strip()
    selected_year = str(request.args.get('academic_year') or current_year or '').strip()

    with db_connection() as conn:
        c = conn.cursor()
        db_execute(
            c,
            """SELECT t.test_id, t.title, t.instructions, t.classname, t.subject, t.term, t.academic_year,
                      t.duration_minutes, t.total_questions, t.questions_to_answer, t.total_marks, t.status, t.created_at,
                      a.attempt_id, a.status AS attempt_status, a.score, a.total_marks AS attempt_total_marks,
                      a.answered_questions, a.total_questions AS attempt_total_questions,
                      a.remaining_seconds, a.last_activity_at,
                      a.started_at, a.submitted_at
               FROM cbt_tests t
               LEFT JOIN cbt_attempts a
                 ON a.school_id = t.school_id
                AND a.test_id = t.test_id
                AND a.student_id = ?
               WHERE t.school_id = ?
                 AND t.status = 'published'
                 AND COALESCE(t.total_questions, 0) > 0
                 AND t.term = ?
                 AND COALESCE(t.academic_year, '') = ?
               ORDER BY t.created_at DESC""",
            (student_id, school_id, selected_term, selected_year),
        )
        rows = c.fetchall() or []

    student_class = (student.get('classname') or '').strip()
    offered_subject_keys = _cbt_student_offered_subject_keys(school_id, student)
    tests = []
    for row in rows:
        rowd = dict(row)
        if not _cbt_class_matches_student(rowd.get('classname', ''), student_class):
            continue
        subject_key = normalize_subject_name(rowd.get('subject', '')).lower()
        if subject_key and offered_subject_keys and subject_key not in offered_subject_keys:
            continue
        attempt_status = (rowd.get('attempt_status') or '').strip().lower()
        rowd['action_mode'] = 'start'
        if attempt_status == 'submitted':
            rowd['action_mode'] = 'review'
        elif attempt_status == 'started':
            rowd['action_mode'] = 'continue'
        tests.append(rowd)

    return render_template(
        'student/student_cbt.html',
        school=school,
        student=student,
        tests=tests,
        selected_term=selected_term,
        selected_year=selected_year,
        current_term=current_term,
        current_year=current_year,
    )


@app.route('/student/cbt/<test_id>/take', methods=['GET', 'POST'])
def student_cbt_take(test_id):
    if session.get('role') != 'student':
        return redirect(url_for('login'))
    if not ensure_cbt_schema():
        flash('CBT module is not available right now. Please retry.', 'error')
        return redirect(url_for('student_cbt'))

    school_id = session.get('school_id')
    student_id = session.get('user_id')
    student = load_student(school_id, student_id)
    if not student:
        flash('Student data not found.', 'error')
        return redirect(url_for('login'))
    school = get_school(school_id) or {}

    test_row = get_cbt_test(school_id, test_id)
    can_take, deny_message = _student_can_take_cbt_test(school_id, student, test_row)
    if not can_take:
        flash(deny_message or 'This CBT is not available to your account.', 'error')
        return redirect(url_for('student_cbt'))

    question_pool = list_cbt_questions(school_id, test_id)
    if not question_pool:
        flash('This CBT has no questions yet.', 'error')
        return redirect(url_for('student_cbt'))

    attempt = get_student_cbt_attempt(school_id, test_id, student_id)
    if request.method == 'POST':
        if not can_take:
            flash('This CBT is closed and cannot be submitted.', 'error')
            return redirect(url_for('student_cbt_take', test_id=test_id))
        try:
            attempt = submit_student_cbt_attempt(
                school_id=school_id,
                test_row=test_row,
                student_id=student_id,
                answers_map=request.form,
                auto_submitted=False,
            )
            flash('CBT submitted successfully.', 'success')
        except Exception as exc:
            flash(str(exc), 'error')
        return redirect(url_for('student_cbt_take', test_id=test_id))

    if not attempt and (test_row.get('status') or '').strip().lower() == 'published':
        attempt = _ensure_student_cbt_attempt(school_id, test_row, student_id)

    selected_questions = question_pool
    answer_map = {}
    draft_answer_map = {}
    remaining_seconds_saved = 0
    if attempt and attempt.get('attempt_id'):
        with db_connection(commit=True) as conn:
            c = conn.cursor()
            _selected_qnos, selected_qrows = _ensure_attempt_question_set_with_cursor(
                c,
                school_id,
                test_row,
                attempt,
                qrows=question_pool,
            )
        selected_questions = selected_qrows or question_pool
        answer_map = list_student_cbt_answers(school_id, attempt.get('attempt_id'))
        draft_answer_map = _load_cbt_draft_answers(attempt.get('draft_answers_json', ''))
        answer_map = _merge_attempt_answer_maps(answer_map, draft_answer_map)
        remaining_seconds_saved = max(0, safe_int(attempt.get('remaining_seconds', 0), 0))

    is_submitted = bool(attempt and (attempt.get('status') or '').strip().lower() == 'submitted')
    accommodation = get_cbt_test_accommodation(school_id, test_id, student_id)
    extra_minutes = safe_int(accommodation.get('extra_minutes', 0), 0) if safe_int(accommodation.get('is_active', 0), 0) else 0
    extra_percent = safe_int(accommodation.get('extra_percent', 0), 0) if safe_int(accommodation.get('is_active', 0), 0) else 0
    duration_seconds = _cbt_duration_seconds_from_questions(
        test_row,
        selected_questions,
        extra_minutes=extra_minutes,
        extra_percent=extra_percent,
    )
    remaining_seconds = duration_seconds
    if not is_submitted and remaining_seconds_saved > 0:
        remaining_seconds = min(duration_seconds, remaining_seconds_saved)

    attempted_count = 0
    correct_count = 0
    wrong_count = 0
    total_count = len(selected_questions or [])
    if is_submitted:
        for q in (selected_questions or []):
            q_no = safe_int(q.get('question_no', 0), 0)
            if q_no <= 0:
                continue
            ans = answer_map.get(q_no, {})
            selected = (ans.get('selected_option') or '').strip().upper()
            if selected:
                attempted_count += 1
                if bool(ans.get('is_correct')):
                    correct_count += 1
                else:
                    wrong_count += 1

    return render_template(
        'student/student_cbt_take.html',
        school=school,
        student=student,
        test=test_row,
        questions=selected_questions,
        question_pool_size=len(question_pool),
        questions_required=len(selected_questions),
        attempt=attempt,
        answer_map=answer_map,
        is_submitted=is_submitted,
        duration_seconds=duration_seconds,
        remaining_seconds=remaining_seconds,
        extra_minutes=extra_minutes,
        extra_percent=extra_percent,
        attempted_count=attempted_count,
        correct_count=correct_count,
        wrong_count=wrong_count,
        total_count=total_count,
    )


@app.route('/student/cbt/<test_id>/autosave', methods=['POST'])
@require_roles('student')
def student_cbt_autosave(test_id):
    if session.get('role') != 'student':
        return jsonify({'ok': False, 'error': 'unauthorized'}), 403
    if not ensure_cbt_schema():
        return jsonify({'ok': False, 'error': 'cbt_unavailable'}), 503
    school_id = session.get('school_id')
    student_id = session.get('user_id')
    student = load_student(school_id, student_id)
    if not student:
        return jsonify({'ok': False, 'error': 'student_not_found'}), 404
    test_row = get_cbt_test(school_id, test_id)
    can_take, deny_message = _student_can_take_cbt_test(school_id, student, test_row)
    if not can_take:
        return jsonify({'ok': False, 'error': deny_message or 'not_allowed'}), 400

    attempt = get_student_cbt_attempt(school_id, test_id, student_id)
    if not attempt:
        attempt = _ensure_student_cbt_attempt(school_id, test_row, student_id)
    if not attempt:
        return jsonify({'ok': False, 'error': 'attempt_not_available'}), 500
    if (attempt.get('status') or '').strip().lower() == 'submitted':
        return jsonify({'ok': True, 'state': 'submitted'}), 200

    question_pool = list_cbt_questions(school_id, test_id)
    if not question_pool:
        return jsonify({'ok': False, 'error': 'no_questions'}), 400
    with db_connection(commit=True) as conn:
        c = conn.cursor()
        _selected_qnos, selected_qrows = _ensure_attempt_question_set_with_cursor(
            c,
            school_id,
            test_row,
            attempt,
            qrows=question_pool,
        )
        draft_map = _build_cbt_draft_answers_map(request.form, selected_qrows or [])
        remaining_seconds = max(0, min(24 * 3600, safe_int(request.form.get('remaining_seconds', 0), 0)))
        db_execute(
            c,
            """UPDATE cbt_attempts
               SET draft_answers_json = ?,
                   remaining_seconds = ?,
                   last_activity_at = CURRENT_TIMESTAMP
               WHERE school_id = ? AND attempt_id = ?""",
            (json.dumps(draft_map), remaining_seconds, school_id, attempt.get('attempt_id', '')),
        )
        integrity_events = _parse_cbt_integrity_events(
            request.form.get('integrity_events_json', request.form.get('_integrity_events_json', ''))
        )
        if integrity_events:
            _log_cbt_attempt_events_with_cursor(
                c,
                school_id,
                attempt.get('attempt_id', ''),
                test_id,
                student_id,
                integrity_events,
            )
            _refresh_cbt_attempt_integrity_flag_with_cursor(
                c,
                school_id,
                attempt.get('attempt_id', ''),
                test_row,
            )
    return jsonify({
        'ok': True,
        'saved_answers': len(draft_map),
        'remaining_seconds': remaining_seconds,
        'saved_at': datetime.utcnow().isoformat() + 'Z',
    }), 200


@app.route('/student/parent-access', methods=['POST'])
@require_roles('student')
@require_rate_limit('student_parent_access', RATE_LIMIT_MUTATION_PER_MIN, 60, redirect_endpoint='student_dashboard', methods=('POST',))
def student_update_parent_access():
    if session.get('role') != 'student':
        return redirect(url_for('login'))
    school_id = session.get('school_id')
    student_id = session.get('user_id')
    student = load_student(school_id, student_id)
    if not student:
        flash('Student data not found.', 'error')
        return redirect(url_for('student_dashboard'))
    if not students_has_parent_access_columns():
        flash('Parent access is not available yet. Ask admin to run latest database migration.', 'error')
        return redirect(url_for('student_dashboard'))
    has_parent_multi_cols = students_has_parent_multi_access_columns()
    parent_slot = (request.form.get('parent_slot', '') or '').strip()
    if parent_slot not in {'1', '2'}:
        flash('Invalid parent access request.', 'error')
        return redirect(url_for('student_dashboard'))

    parent1_name = normalize_person_name(request.form.get('parent_name', ''))
    parent1_phone = normalize_parent_phone(request.form.get('parent_phone', ''))
    parent1_gender = normalize_parent_gender(request.form.get('parent_gender', ''))
    parent1_password = (request.form.get('parent_password', '') or '').strip()
    parent1_confirm = (request.form.get('confirm_parent_password', '') or '').strip()

    parent2_name = normalize_person_name(request.form.get('parent_name_2', ''))
    parent2_phone = normalize_parent_phone(request.form.get('parent_phone_2', ''))
    parent2_gender = normalize_parent_gender(request.form.get('parent_gender_2', ''))
    parent2_password = (request.form.get('parent_password_2', '') or '').strip()
    parent2_confirm = (request.form.get('confirm_parent_password_2', '') or '').strip()

    has_existing_parent1 = bool((student.get('parent_phone', '') or '').strip() and (student.get('parent_password_hash', '') or '').strip())
    has_existing_parent2 = bool((student.get('parent_phone_2', '') or '').strip() and (student.get('parent_password_hash_2', '') or '').strip())
    if parent_slot == '1':
        if has_existing_parent1:
            flash('Parent 1 is already added. Students cannot edit parent details after adding.', 'error')
            return redirect(url_for('student_dashboard'))
        if not parent1_name:
            flash('Parent 1 name is required.', 'error')
            return redirect(url_for('student_dashboard'))
        if not parent1_phone or not parent1_password:
            flash('Parent 1 phone and password are required.', 'error')
            return redirect(url_for('student_dashboard'))
        if not is_valid_parent_phone(parent1_phone):
            flash('Enter a valid Parent 1 phone number.', 'error')
            return redirect(url_for('student_dashboard'))
        if not parent1_gender:
            flash('Select Parent 1 gender.', 'error')
            return redirect(url_for('student_dashboard'))
        if len(parent1_password) < 6:
            flash('Parent 1 password must be at least 6 characters.', 'error')
            return redirect(url_for('student_dashboard'))
        if parent1_password != parent1_confirm:
            flash('Parent 1 passwords do not match.', 'error')
            return redirect(url_for('student_dashboard'))
        if has_existing_parent2 and parent1_phone == normalize_parent_phone(student.get('parent_phone_2', '')):
            flash('Parent 1 phone cannot match Parent 2 phone.', 'error')
            return redirect(url_for('student_dashboard'))
        student['parent_name'] = parent1_name
        student['parent_phone'] = parent1_phone
        student['parent_password_hash'] = hash_password(parent1_password)
        student['parent_gender'] = parent1_gender
        save_student(school_id, student_id, student)
        flash('Parent 1 added successfully.', 'success')
        return redirect(url_for('student_dashboard'))

    # Parent 2 add-only flow.
    if not has_parent_multi_cols:
        flash('Secondary parent access is not available yet. Run migration/startup schema updates and retry.', 'error')
        return redirect(url_for('student_dashboard'))
    if not has_existing_parent1:
        flash('Add Parent 1 first before adding Parent 2.', 'error')
        return redirect(url_for('student_dashboard'))
    if has_existing_parent2:
        flash('Parent 2 is already added. Students cannot edit parent details after adding.', 'error')
        return redirect(url_for('student_dashboard'))
    if not parent2_name:
        flash('Parent 2 name is required.', 'error')
        return redirect(url_for('student_dashboard'))
    if not parent2_phone or not parent2_password:
        flash('Parent 2 phone and password are required.', 'error')
        return redirect(url_for('student_dashboard'))
    if not is_valid_parent_phone(parent2_phone):
        flash('Enter a valid Parent 2 phone number.', 'error')
        return redirect(url_for('student_dashboard'))
    if not parent2_gender:
        flash('Select Parent 2 gender.', 'error')
        return redirect(url_for('student_dashboard'))
    if len(parent2_password) < 6:
        flash('Parent 2 password must be at least 6 characters.', 'error')
        return redirect(url_for('student_dashboard'))
    if parent2_password != parent2_confirm:
        flash('Parent 2 passwords do not match.', 'error')
        return redirect(url_for('student_dashboard'))
    existing_parent1_phone = normalize_parent_phone(student.get('parent_phone', ''))
    if parent2_phone == existing_parent1_phone:
        flash('Parent 2 phone must be different from Parent 1 phone.', 'error')
        return redirect(url_for('student_dashboard'))
    student['parent_name_2'] = parent2_name
    student['parent_phone_2'] = parent2_phone
    student['parent_password_hash_2'] = hash_password(parent2_password)
    student['parent_gender_2'] = parent2_gender
    save_student(school_id, student_id, student)
    flash('Parent 2 added successfully.', 'success')
    return redirect(url_for('student_dashboard'))

@app.route('/student/view-result')
def student_view_result():
    if session.get('role') != 'student':
        return redirect(url_for('login'))
    
    school_id = session.get('school_id')
    school = get_school(school_id) or {}
    current_term = get_current_term(school)
    current_year = (school or {}).get('academic_year', '')
    student_id = session.get('user_id')
    live_student = load_student(school_id, student_id)
    if not live_student:
        flash('Student data not found.', 'error')
        return redirect(url_for('login'))
    requested_term = (request.args.get('term', '') or '').strip()
    selected_class = (request.args.get('class_name', '') or '').strip()
    term_notice = ''

    all_published_terms = get_published_terms_for_student(school_id, student_id)
    available_result_classes = sorted({
        (t.get('classname') or '').strip()
        for t in all_published_terms
        if (t.get('classname') or '').strip()
    })
    if selected_class and selected_class not in available_result_classes:
        term_notice = f'No published results found for class "{selected_class}".'
        selected_class = ''

    published_terms = filter_visible_terms_for_student(
        school,
        get_published_terms_for_student(school_id, student_id, classname=selected_class),
    )
    if not published_terms:
        if safe_int((school or {}).get('operations_enabled', 1), 1):
            flash('No published result available yet.', 'error')
        else:
            flash('Current term results are hidden while operations are OFF. Only previous published results are available.', 'error')
        return redirect(url_for('student_dashboard'))

    if requested_term:
        target_entry = resolve_requested_published_term(
            published_terms,
            requested_term,
            current_term=current_term,
            current_year=current_year,
        )
        if not target_entry:
            term_notice = f'{requested_term} result is not published for you.'
            target_entry = pick_default_published_term(published_terms, current_term, current_year)
    else:
        target_entry = pick_default_published_term(published_terms, current_term, current_year)
    target_term = target_entry['term']
    target_year = target_entry.get('academic_year', '')
    current_term_token = target_entry['token']

    snapshot = load_published_student_result(
        school_id,
        student_id,
        target_term,
        target_year,
        classname=selected_class,
    )
    if not snapshot:
        flash('Published result snapshot not found.', 'error')
        return redirect(url_for('student_dashboard'))
    record_result_view(school_id, student_id, target_term, snapshot.get('academic_year', target_year))

    exam_config = get_assessment_config_for_class(school_id, snapshot.get('classname', ''))
    class_results = load_published_class_results(school_id, snapshot.get('classname', ''), target_term, target_year, school=school)
    position, subject_positions = build_positions_from_published_results(
        school=school,
        classname=snapshot.get('classname', ''),
        term=target_term,
        class_results=class_results,
        student_id=student_id,
        student_stream=snapshot.get('stream', ''),
        subjects=snapshot.get('subjects', []),
    )

    student_view = {
        'first_name': snapshot.get('firstname', ''),
        'student_id': student_id,
        'date_of_birth': (live_student.get('date_of_birth', '') or '').strip(),
        'gender': (live_student.get('gender', '') or '').strip(),
        'class_name': snapshot.get('classname', ''),
        'class_size': len(class_results or []),
        'term': target_term,
        'academic_year': target_year,
        'number_of_subject': snapshot.get('number_of_subject', 0),
        'subjects': snapshot.get('scores', {}),
        'behaviour_assessment': snapshot.get('behaviour_assessment', {}),
        'teacher_comment': snapshot.get('teacher_comment', ''),
        'principal_comment': snapshot.get('principal_comment', ''),
        'average_marks': snapshot.get('average_marks', 0),
        'Grade': snapshot.get('Grade', 'F'),
        'Status': snapshot.get('Status', 'Fail'),
    }
    student_view.update(
        build_result_term_attendance_data(
            school_id=school_id,
            student_id=student_id,
            classname=snapshot.get('classname', ''),
            term=target_term,
            academic_year=target_year,
        )
    )
    result_max_tests = detect_max_tests_from_scores(snapshot.get('scores', {}), school.get('max_tests', 3))
    signoff = get_result_signoff_details(
        school_id,
        snapshot.get('classname', ''),
        target_term,
        target_year,
    )
    teacher_signature = signoff.get('teacher_signature', '')
    principal_signature = signoff.get('principal_signature', '')
    teacher_name = signoff.get('teacher_name', '')
    principal_name = signoff.get('principal_name', '')
    verify_ctx = build_result_verification_context(
        school_id=school_id,
        student_id=student_id,
        term=target_term,
        academic_year=target_year,
        classname=snapshot.get('classname', ''),
    )

    current_index = next((i for i, item in enumerate(published_terms) if item['token'] == current_term_token), 0)
    prev_term = published_terms[current_index - 1] if current_index > 0 else None
    next_term = published_terms[current_index + 1] if current_index < len(published_terms) - 1 else None

    return render_template('student/student_result.html', 
                         student=student_view,
                         school=school,
                         position=position,
                         subject_positions=subject_positions,
                         published_terms=published_terms,
                         current_term_token=current_term_token,
                         available_result_classes=available_result_classes,
                         selected_result_class=selected_class,
                         term_notice=term_notice,
                         term_view_endpoint='student_view_result',
                         prev_term=prev_term,
                         next_term=next_term,
                         teacher_signature=teacher_signature,
                         teacher_name=teacher_name,
                         principal_signature=principal_signature,
                          principal_name=principal_name,
                          result_max_tests=result_max_tests,
                          exam_config=exam_config,
                          verification_url=verify_ctx.get('verification_url', ''),
                          verification_qr_url=verify_ctx.get('verification_qr_url', ''),
                          now=datetime.now())


def _parent_allowed_student_keys():
    keys = session.get('parent_student_keys') or []
    session_keys = {str(k) for k in keys if isinstance(k, str) and '::' in k}
    if not session_keys:
        return set()
    parent_phone = normalize_parent_phone(session.get('parent_phone', ''))
    if not parent_phone:
        return set()
    # Defense-in-depth: only keep students still linked to this parent phone.
    # This blocks stale session keys after parent unlink/relink changes.
    linked_keys = {
        f"{(row.get('school_id') or '').strip()}::{(row.get('student_id') or '').strip()}"
        for row in get_parent_students_by_phone(parent_phone)
        if (row.get('school_id') or '').strip() and (row.get('student_id') or '').strip()
    }
    return session_keys.intersection(linked_keys)

def _build_parent_sidebar_context(limit_per_school=120):
    allowed_keys = _parent_allowed_student_keys()
    if not allowed_keys:
        return {
            'children': [],
            'parent_theme_accent': '#1F7A8C',
            'parent_messages': [],
            'unread_parent_messages': 0,
        }
    key_pairs = []
    student_ids_by_school = {}
    for key in sorted(allowed_keys):
        if '::' not in key:
            continue
        school_id, student_id = key.split('::', 1)
        school_id = (school_id or '').strip()
        student_id = (student_id or '').strip()
        if not school_id or not student_id:
            continue
        key_pairs.append((key, school_id, student_id))
        student_ids_by_school.setdefault(school_id, []).append(student_id)

    schools_by_id = {sid: (get_school(sid) or {}) for sid in student_ids_by_school.keys()}
    students_by_key = {}
    for sid, student_ids in student_ids_by_school.items():
        rows = load_students_for_student_ids(sid, student_ids)
        for student_id, student in rows.items():
            students_by_key[f'{sid}::{student_id}'] = student

    children = []
    for key, school_id, student_id in key_pairs:
        student = students_by_key.get(key)
        if not student:
            continue
        school = schools_by_id.get(school_id, {})
        children.append({
            'key': key,
            'school_id': school_id,
            'school_name': (school or {}).get('school_name', school_id),
            'student_id': student_id,
            'firstname': student.get('firstname', ''),
            'classname': student.get('classname', ''),
            'stream': student.get('stream', ''),
            'subjects': student.get('subjects', []),
        })
    children.sort(key=lambda row: ((row.get('firstname') or '').lower(), (row.get('student_id') or '').lower()))

    parent_theme_accent = '#1F7A8C'
    if children:
        first_school_id = (children[0].get('school_id') or '').strip()
        first_school = schools_by_id.get(first_school_id, {}) if first_school_id else {}
        parent_theme_accent = normalize_hex_color(first_school.get('theme_accent_color', ''), '#1F7A8C')

    parent_messages = get_parent_messages_for_children(
        parent_phone=session.get('parent_phone', ''),
        children=children,
        limit_per_school=max(40, int(limit_per_school or 120)),
    )
    unread_parent_messages = sum(1 for row in parent_messages if not row.get('is_read'))
    return {
        'children': children,
        'parent_theme_accent': parent_theme_accent,
        'parent_messages': parent_messages,
        'unread_parent_messages': unread_parent_messages,
    }


