@app.route('/change_password', methods=['GET', 'POST'])
@app.route('/change-password', methods=['GET', 'POST'])
def change_password():
    """Backward-compatible password endpoint for legacy templates."""
    role = (session.get('role') or '').strip().lower()
    if role == 'parent':
        if request.method == 'POST':
            return parent_change_password()
        flash('Use the parent dashboard password form to change password.', 'error')
        return redirect(url_for('parent_dashboard'))

    if 'user_id' not in session:
        return redirect(url_for('login'))

    if role == 'super_admin':
        return super_admin_change_password()
    if role == 'school_admin':
        # Reuse the dedicated school-admin handler for both GET and POST.
        return school_admin_change_password()
    if role == 'student':
        return student_change_password()

    flash('Password change is not available on this page.', 'error')
    return redirect(url_for('menu'))

@app.route('/view_students')
@require_roles('teacher', 'school_admin')
def view_students():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    role = (session.get('role') or '').strip().lower()
    if role not in {'teacher', 'school_admin'}:
        return redirect(url_for('menu'))
    
    school_id = session.get('school_id')
    if not school_id:
        return redirect(url_for('login'))
    school = get_school(school_id) or {}
    grade_cfg = get_grade_config(school_id)
    current_term = get_current_term(school)

    selected_class = canonicalize_classname(request.args.get('class', '').strip())
    selected_term = request.args.get('term', '').strip()
    try:
        per_page = int((request.args.get('per_page', '') or '50').strip())
    except (TypeError, ValueError):
        per_page = 50
    per_page = max(10, min(per_page, 200))
    try:
        page = int((request.args.get('page', '') or '1').strip())
    except (TypeError, ValueError):
        page = 1
    page = max(1, page)
    if not selected_term and role == 'teacher':
        selected_term = current_term

    if session.get('role') == 'teacher':
        teacher_id = session.get('user_id')
        current_year = (school or {}).get('academic_year', '')
        class_owner_set = set(get_teacher_classes(school_id, teacher_id, term=selected_term, academic_year=current_year))
        class_set = set(class_owner_set)
        subject_rows = get_teacher_subject_assignments(
            school_id,
            teacher_id=teacher_id,
            term=selected_term,
            academic_year=current_year,
        )
        class_set.update({r.get('classname', '') for r in subject_rows if r.get('classname', '')})
        available_classes, available_terms = get_student_filter_options(school_id, classnames=class_set)
        if selected_class and selected_class not in set(available_classes):
            selected_class = ''
        if selected_term and selected_term not in set(available_terms):
            selected_term = ''
        students_data = load_students_for_classes(school_id, class_set, term_filter=selected_term)
        teacher_result_classes_lower = {(c or '').strip().lower() for c in class_owner_set}
        subject_map_by_class = {}
        for row in subject_rows:
            cls = (row.get('classname') or '').strip()
            subj = normalize_subject_name(row.get('subject', ''))
            if not cls or not subj:
                continue
            subject_map_by_class.setdefault(cls, set()).add(subj)
    else:
        # School admin path: query only currently requested class/term when provided.
        available_classes, available_terms = get_student_filter_options(school_id)
        if selected_class and selected_class not in set(available_classes):
            selected_class = ''
        if selected_term and selected_term not in set(available_terms):
            selected_term = ''
        students_data = load_students(school_id, class_filter=selected_class, term_filter=selected_term)
        # School admin usability fallback: if a class is selected but no rows match the selected term,
        # automatically show that class across all terms instead of appearing empty.
        if selected_class and selected_term and not students_data:
            class_only_students = load_students(school_id, class_filter=selected_class, term_filter='')
            if class_only_students:
                students_data = class_only_students
                selected_term = ''
        teacher_result_classes_lower = set()
        class_owner_set = set()
        subject_map_by_class = {}

    if selected_class:
        students_data = {sid: s for sid, s in students_data.items() if (s.get('classname', '') or '').strip() == selected_class}
    if selected_term:
        students_data = {sid: s for sid, s in students_data.items() if (s.get('term', '') or '').strip() == selected_term}

    students = []
    for student_id, student_data in students_data.items():
        if session.get('role') == 'teacher':
            classname = (student_data.get('classname', '') or '').strip()
            is_class_owner = classname in class_owner_set
            subject_actions = []
            if not is_class_owner:
                allowed_subjects = subject_map_by_class.get(classname, set())
                if not allowed_subjects:
                    continue
                offered_subjects = normalize_subjects_list(student_data.get('subjects', []))
                subject_actions = [s for s in offered_subjects if s in allowed_subjects]
                if not subject_actions:
                    continue
        else:
            is_class_owner = False
            subject_actions = []
        scores = student_data.get('scores', {}) if isinstance(student_data.get('scores', {}), dict) else {}
        average_marks = compute_average_marks_from_scores(scores, subjects=student_data.get('subjects', []))
        grade = grade_from_score(average_marks, grade_cfg)
        status = status_from_score(average_marks, grade_cfg)

        students.append({
            'first_name': student_data.get('firstname', ''),
            'student_id': student_id,
            'class_name': student_data.get('classname', ''),
            'term': student_data.get('term', ''),
            'stream': student_data.get('stream', ''),
            'subjects': scores,
            'can_edit_full': bool(is_class_owner),
            'subject_actions': subject_actions,
            'average_marks': average_marks,
            'Grade': grade,
            'Status': status
        })

    students.sort(
        key=lambda s: (
            (s.get('class_name', '') or '').strip().lower(),
            (s.get('first_name', '') or '').strip().lower(),
            (s.get('student_id', '') or '').strip().lower(),
        )
    )

    positions = calculate_positions(students, school.get('ss_ranking_mode', 'together'), school=school)
    total_students = len(students)
    grade_a_count = sum(1 for s in students if s.get('Grade') == 'A')
    pass_count = sum(1 for s in students if s.get('Status') == 'Pass')
    overall_average = (sum(s.get('average_marks', 0) for s in students) / total_students) if total_students else 0
    total_pages = max(1, (total_students + per_page - 1) // per_page)
    if page > total_pages:
        page = total_pages
    start_idx = (page - 1) * per_page
    end_idx = start_idx + per_page
    page_students = students[start_idx:end_idx]

    return render_template(
        'shared/view_students.html',
        students=page_students,
        positions=positions,
        total_students=total_students,
        grade_a_count=grade_a_count,
        pass_count=pass_count,
        overall_average=overall_average,
        available_classes=available_classes,
        available_terms=available_terms,
        selected_class=selected_class,
        selected_term=selected_term,
        teacher_result_classes_lower=teacher_result_classes_lower,
        page=page,
        total_pages=total_pages,
        per_page=per_page
    )

@app.route('/assistant/guide', methods=['POST'])
def assistant_guide():
    role = _current_role()
    if role not in {'super_admin', 'school_admin', 'teacher', 'student', 'parent'}:
        body = {'ok': False, 'error': 'unauthorized'}
        return Response(json.dumps(body), status=403, mimetype='application/json')

    client_ip = (get_client_ip() or request.remote_addr or 'unknown').strip()
    allowed, retry_after = _rate_limit_consume(
        key=f'assistant_guide:{role}:{client_ip}',
        limit=APP_ASSISTANT_RATE_LIMIT_PER_MIN,
        window_seconds=60,
    )
    if not allowed:
        body = {
            'ok': False,
            'error': f'Too many assistant requests. Please wait about {retry_after} seconds and try again.',
        }
        return Response(json.dumps(body), status=429, mimetype='application/json')

    question = (request.form.get('question', '') or '').strip()
    response_mode = (request.form.get('response_mode', '') or '').strip().lower()
    default_mode = _assistant_default_response_mode_for_role(role)
    if response_mode not in APP_ASSISTANT_RESPONSE_MODES:
        response_mode = get_assistant_user_preference(role=role, key='response_mode', default=default_mode)
    if response_mode not in APP_ASSISTANT_RESPONSE_MODES:
        response_mode = default_mode
    set_assistant_user_preference(role=role, key='response_mode', value=response_mode)
    history_raw = (request.form.get('history', '') or '').strip()
    history_rows = []
    if history_raw:
        try:
            parsed_history = json.loads(history_raw)
            if isinstance(parsed_history, list):
                for item in parsed_history[-8:]:
                    if not isinstance(item, dict):
                        continue
                    role_val = (item.get('role') or '').strip().lower()
                    text_val = str(item.get('text') or '').strip()
                    if role_val in {'user', 'assistant'} and text_val:
                        history_rows.append({'role': role_val, 'text': text_val[:400]})
        except Exception:
            history_rows = []
    memory_rows = get_assistant_memory_history(
        role=role,
        days=APP_ASSISTANT_MEMORY_DAYS,
        max_exchanges=APP_ASSISTANT_MEMORY_MAX_EXCHANGES,
    )
    merged_history = []
    for item in (memory_rows or []) + (history_rows or []):
        if not isinstance(item, dict):
            continue
        role_val = (item.get('role') or '').strip().lower()
        text_val = str(item.get('text') or '').strip()
        if role_val in {'user', 'assistant'} and text_val:
            merged_history.append({'role': role_val, 'text': text_val[:400]})
    if len(merged_history) > 16:
        merged_history = merged_history[-16:]
    if not question:
        body = {'ok': False, 'error': 'Type your question first. You can also paste an error message or traceback.'}
        return Response(json.dumps(body), status=400, mimetype='application/json')

    if len(question) > APP_ASSISTANT_MAX_QUESTION_CHARS:
        body = {
            'ok': False,
            'error': f'Your message is too long ({len(question)} chars). Please shorten it to {APP_ASSISTANT_MAX_QUESTION_CHARS} chars or less.',
        }
        return Response(json.dumps(body), status=422, mimetype='application/json')

    teacher_scope = _assistant_get_teacher_scope() if role == 'teacher' else None
    source_page = (request.form.get('page', '') or '').strip()
    page_context = (request.form.get('page_context', '') or '').strip()[:260]
    try:
        payload = _assistant_build_response(
            role,
            question,
            teacher_scope=teacher_scope,
            source_page=source_page,
            page_context=page_context,
            conversation_history=merged_history,
            response_mode=response_mode,
        )
    except TypeError:
        # Backward-compatible path for older/mocked helper signatures.
        payload = _assistant_build_response(
            role,
            question,
            teacher_scope=teacher_scope,
            source_page=source_page,
            conversation_history=merged_history,
            response_mode=response_mode,
        )
    school_id = (session.get('school_id') or '').strip()
    learning_signal = (
        get_assistant_learning_signal(
            school_id=school_id,
            role=role,
            question=question,
            source_page=source_page,
            days=45,
        )
        if school_id and role != 'super_admin'
        else {'needs_update': False}
    )
    if learning_signal.get('needs_update'):
        steps_rows = [str(s).strip() for s in (payload.get('steps') or []) if str(s).strip()]
        learning_step = 'Learning signal: this question has mixed feedback. Confirm the exact page/menu before applying changes.'
        if learning_step not in steps_rows:
            steps_rows.insert(0, learning_step)
        payload['steps'] = steps_rows[:6]
        payload['confidence'] = round(max(0.35, min(float(payload.get('confidence') or 0.0), 0.72)), 3)
        if int(learning_signal.get('unresolved_hits') or 0) >= 2:
            payload['unresolved'] = True
        if not (payload.get('next_question') or '').strip():
            payload['next_question'] = 'Which exact page are you on now so I can guide more precisely?'
    payload['learning_signal'] = {
        'needs_update': bool(learning_signal.get('needs_update')),
        'helpful': int(learning_signal.get('helpful') or 0),
        'not_helpful': int(learning_signal.get('not_helpful') or 0),
        'unresolved_hits': int(learning_signal.get('unresolved_hits') or 0),
        'avg_confidence': float(learning_signal.get('avg_confidence') or 0.0),
    }
    boosted_prompts = get_assistant_prompt_boosts(
        school_id,
        role=role,
        days=45,
        limit=2,
        source_page=source_page,
    ) if school_id and role != 'super_admin' else []
    if boosted_prompts:
        merged_prompts = []
        seen_prompts = set()
        for item in list(boosted_prompts) + list(payload.get('quick_prompts') or []):
            text = str(item or '').strip()
            key = _assistant_normalize_text(text)
            if text and key and key not in seen_prompts:
                merged_prompts.append(text)
                seen_prompts.add(key)
            if len(merged_prompts) >= 6:
                break
        payload['quick_prompts'] = merged_prompts
    llm_available = bool((os.environ.get('OPENAI_API_KEY', '') or '').strip())
    should_try_llm = APP_ASSISTANT_ENABLE_OPENAI and llm_available and not payload.get('action_blocked')
    if should_try_llm:
        llm_prompt_question = question
        if page_context:
            llm_prompt_question = f"{question}\n\nPage context: {page_context}"
        llm_payload = _assistant_call_openai(
            role,
            llm_prompt_question,
            payload.get('links') or [],
            knowledge_context=payload.get('knowledge_context', ''),
            response_mode=response_mode,
        )
        if llm_payload:
            payload['answer'] = _assistant_enforce_guide_only_text(llm_payload.get('answer') or payload.get('answer', ''))
            payload['steps'] = llm_payload.get('steps') or payload.get('steps', [])
            payload['used_llm'] = True
        else:
            payload['used_llm'] = False
    else:
        payload['used_llm'] = False
    log_assistant_query(
        role=role,
        question=question,
        source_page=source_page,
        used_llm=bool(payload.get('used_llm')),
        confidence=float(payload.get('confidence') or 0.0),
        unresolved=bool(payload.get('unresolved')),
        response_mode=response_mode,
        answer_version=APP_ASSISTANT_ANSWER_VERSION,
    )
    save_assistant_memory_exchange(
        role=role,
        question=question,
        answer=(payload.get('answer') or ''),
        source_page=source_page,
        response_mode=response_mode,
    )
    payload.pop('needs_llm', None)
    payload.pop('action_blocked', None)
    payload.pop('knowledge_context', None)
    payload['ok'] = True
    payload['role'] = role
    payload['answer_version'] = APP_ASSISTANT_ANSWER_VERSION
    return Response(json.dumps(payload), mimetype='application/json')

